# Configure the AWS Provider
# Note: Route 53 query logging requires the CloudWatch Log Group to be located in the us-east-1 region.
provider "aws" {
  region = "us-east-1"
}

# Create the Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# Create the CloudWatch Log Group
resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "aws_route53_example_com"
  retention_in_days = 30
}

# Define the IAM Policy Document for CloudWatch Logs Resource Policy
data "aws_iam_policy_document" "route53_query_logging_policy_doc" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:us-east-1:*:log-group:*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

# Create the CloudWatch Logs Resource Policy to allow Route 53 to write logs
resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_document = data.aws_iam_policy_document.route53_query_logging_policy_doc.json
  policy_name     = "route53-query-logging-policy"
}

# Set up the Route 53 Query Logging
resource "aws_route53_query_log" "main" {
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id

  # Ensure the resource policy is in place before creating the query log
  depends_on = [aws_cloudwatch_log_resource_policy.route53_query_logging_policy]
}

