# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a primary VPC
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "primary-vpc"
  }
}

# Create a secondary VPC to associate with the hosted zone
resource "aws_vpc" "secondary" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "secondary-vpc"
  }
}

# Create a Private Route 53 Hosted Zone
# Note: A private hosted zone must be associated with at least one VPC at creation time.
resource "aws_route53_zone" "private" {
  name = "internal.example.com"

  vpc {
    vpc_id = aws_vpc.primary.id
  }

  lifecycle {
    ignore_changes = [vpc]
  }
}

# Associate the private hosted zone with the secondary VPC
# This resource is used to manage associations for VPCs that are not defined 
# in the initial 'aws_route53_zone' resource block.
resource "aws_route53_zone_association" "secondary_association" {
  zone_id = aws_route53_zone.private.zone_id
  vpc_id  = aws_vpc.secondary.id
}

