provider "aws" {
  region = "us-east-1"
}

# Create a VPC and subnets to support the Load Balancer
resource "aws_vpc" "main_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Application Load Balancer named "main"
resource "aws_lb" "main" {
  name               = "main"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [] # Add security group IDs here
  subnets            = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "main"
  }
}

# Route 53 Hosted Zone named "primary"
# Note: "primary.com" is used as a placeholder domain name
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"
}

# Route 53 Record pointing to the Load Balancer
resource "aws_route53_record" "lb_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.primary.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}

