# Provider Definitions
provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

# Primary DB Instance (us-west-1)
resource "aws_db_instance" "primary" {
  provider             = aws.main
  identifier           = "primary"
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "maindb"
  username             = "admin"
  password             = "securepassword123"
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true

  # Required for replication
  backup_retention_period = 7
}

# Replica DB Instance (us-east-1)
resource "aws_db_instance" "replica_us_east" {
  provider            = aws.us-east
  identifier          = "replica-us-east"
  instance_class      = "db.t3.micro"
  replicate_source_db = aws_db_instance.primary.arn
  skip_final_snapshot = true
}

# Replica DB Instance (eu-central-1)
resource "aws_db_instance" "replica_eu_central" {
  provider            = aws.eu-central
  identifier          = "replica-eu-central"
  instance_class      = "db.t3.micro"
  replicate_source_db = aws_db_instance.primary.arn
  skip_final_snapshot = true
}

# Replica DB Instance (ap-southeast-1)
resource "aws_db_instance" "replica_ap_southeast" {
  provider            = aws.ap-southeast
  identifier          = "replica-ap-southeast"
  instance_class      = "db.t3.micro"
  replicate_source_db = aws_db_instance.primary.arn
  skip_final_snapshot = true
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name     = "example.com"
}

# Weighted Routing Records for Replicas
resource "aws_route53_record" "replica_us_east_weighted" {
  provider = aws.main
  zone_id  = aws_route53_zone.main.zone_id
  name     = "db-replicas.example.com"
  type     = "CNAME"
  ttl      = "60"

  weighted_routing_policy {
    weight = 33
  }

  set_identifier = "replica_us_east"
  records        = [aws_db_instance.replica_us_east.address]
}

resource "aws_route53_record" "replica_eu_central_weighted" {
  provider = aws.main
  zone_id  = aws_route53_zone.main.zone_id
  name     = "db-replicas.example.com"
  type     = "CNAME"
  ttl      = "60"

  weighted_routing_policy {
    weight = 33
  }

  set_identifier = "replica_eu_central"
  records        = [aws_db_instance.replica_eu_central.address]
}

resource "aws_route53_record" "replica_ap_southeast_weighted" {
  provider = aws.main
  zone_id  = aws_route53_zone.main.zone_id
  name     = "db-replicas.example.com"
  type     = "CNAME"
  ttl      = "60"

  weighted_routing_policy {
    weight = 34
  }

  set_identifier = "replica_ap_southeast"
  records        = [aws_db_instance.replica_ap_southeast.address]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
      configuration_aliases = [ aws.main, aws.us_east, aws.eu_central, aws.ap_southeast ]
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  alias = "main"
  region = "us-west-2" 

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "us_east"
  region = "us-east-1" # Example region for US East

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1" # Example region for EU Central

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "ap_southeast"
  region = "ap-southeast-1" # Example region for AP Southeast

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier = "master"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_us_east" {
  provider             = aws.us_east
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-us-east"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_eu_central" {
  provider             = aws.eu_central
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-eu-central"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider             = aws.ap_southeast
  replicate_source_db  = aws_db_instance.primary.arn

  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-ap-southeast"
  skip_final_snapshot  = true
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_us_east_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "us.east.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_us_east.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-us-east"
}

resource "aws_route53_record" "replica_eu_central_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "eu.central.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_eu_central.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-eu-central"
}

resource "aws_route53_record" "replica_ap_southeast_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "ap.southeast.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_ap_southeast.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-ap-southeast"
}

