terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Networking setup for RDS
resource "aws_vpc" "vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

# RDS Instances
resource "aws_db_instance" "internal" {
  identifier           = "internal"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "password_internal"
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = false
  skip_final_snapshot  = true
}

resource "aws_db_instance" "public" {
  identifier           = "public"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "password_public"
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = true
  skip_final_snapshot  = true
}

# Route 53 Hosted Zones
resource "aws_route53_zone" "private" {
  name = "private"
  vpc {
    vpc_id = aws_vpc.vpc.id
  }
}

resource "aws_route53_zone" "public" {
  name = "public"
}

# Route 53 Records
# Inside users resolve "db.private" to the internal RDS endpoint
resource "aws_route53_record" "internal_record" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.private"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
}

# Outside users resolve "db.public" to the public RDS endpoint
resource "aws_route53_record" "public_record" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db.public"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region = "us-east-1" 
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a VPC for internal resources
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/24"
}


# RDS instances
resource "aws_db_instance" "internal" {
  # Internal DB configuration
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier =  "internal"
  username             = "user"
  password             = "password"
  db_subnet_group_name = aws_db_subnet_group.main.name
  skip_final_snapshot  = true
}

resource "aws_db_instance" "public" {
  # Public DB configuration
  publicly_accessible  = true
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  identifier = "public"
  username             = "user"
  password             = "password"
