  name = "private"
  vpc {
    vpc_id = aws_vpc.vpc.id
  }
}

resource "aws_route53_zone" "public" {
  name = "public"
}

# Route 53 Records
# Inside users resolve "db.private" to the internal RDS endpoint
resource "aws_route53_record" "internal_record" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.private"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.address]
}

# Outside users resolve "db.public" to the public RDS endpoint
