      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Default provider
provider "aws" {
  region = "us-west-2"
}

# Provider for US West region
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

# Provider for EU Central region
provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

# --- IAM Resources (Global) ---
# Elastic Beanstalk requires a service role and an instance profile

resource "aws_iam_role" "eb_instance_role" {
  name = "aws-elasticbeanstalk-ec2-role-multi-region"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "eb-instance-profile-multi-region"
  role = aws_iam_role.eb_instance_role.name
}

# --- US West Infrastructure ---

resource "aws_elastic_beanstalk_application" "us_west_app" {
  provider = aws.us_west
  name     = "multi-region-app-us-west"
}

resource "aws_elastic_beanstalk_environment" "us_west_env" {
  provider            = aws.us_west
  name                = "us-west"
  application         = aws_elastic_beanstalk_application.us_west_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.12"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }
}

# --- EU Central Infrastructure ---

resource "aws_elastic_beanstalk_application" "eu_central_app" {
  provider = aws.eu_central
  name     = "multi-region-app-eu-central"
}

resource "aws_elastic_beanstalk_environment" "eu_central_env" {
  provider            = aws.eu_central
  name                = "eu-central"
  application         = aws_elastic_beanstalk_application.eu_central_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.12"

