  }
}

# --- Route 53 Geolocation Configuration ---

# Assuming the hosted zone for your domain already exists
data "aws_route53_zone" "selected" {
  name         = "example.com."
  private_zone = false
}

# Route users in North America to us-west-2
resource "aws_route53_record" "us_geo_record" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.us_west_env.cname]

  set_identifier = "us-west-geo"
  geolocation_routing_policy {
    continent = "NA"
  }
}

# Route users in Europe to eu-central-1
resource "aws_route53_record" "eu_geo_record" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.eu_central_env.cname]

  set_identifier = "eu-central-geo"
  geolocation_routing_policy {
    continent = "EU"
  }
}

# Default record for users outside North America and Europe
resource "aws_route53_record" "default_geo_record" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.us_west_env.cname]

  set_identifier = "default-geo"
  geolocation_routing_policy {
    country = "*"
  }
}

