# Terraform configuration for Blue-Green Elastic Beanstalk deployment with RDS

provider "aws" {
  region = "us-east-1"
}

# --- Database Section ---

resource "aws_db_instance" "database" {
  allocated_storage         = 20
  identifier                = "my-rds-instance"
  db_name                   = "my_db"
  engine                    = "postgres"
  engine_version            = "14"
  instance_class            = "db.t3.micro"
  username                  = "admin"
  password                  = "securepassword123" # Should be handled via secrets manager in production
  skip_final_snapshot       = false
  final_snapshot_identifier = "my-db-final-snapshot-${timestamp()}"
  backup_retention_period   = 7
  copy_tags_to_snapshot     = true
  publicly_accessible       = false
}

# Resource to create a snapshot before significant changes/deployment logic
resource "aws_db_snapshot" "pre_deployment_snapshot" {
  db_instance_identifier = aws_db_instance.database.id
  db_snapshot_identifier = "pre-deploy-snapshot-${formatdate("YYYYMMDDhhmmss", timestamp())}"
}

# --- IAM Section ---

# Referenced instance profile name: ec2_eb_profile1
resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_role.name
}

resource "aws_iam_role" "eb_role" {
  name = "eb_instance_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

# --- Elastic Beanstalk Section ---

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application for Blue-Green deployment"
}

# Common settings for environments
locals {
  eb_settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = "ec2_eb_profile1"
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_HOST"
      value     = aws_db_instance.database.address
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_NAME"
      value     = "my_db"
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_USER"
      value     = aws_db_instance.database.username
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_PASSWORD"
      value     = aws_db_instance.database.password
    }
  ]
}

# Blue Environment
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "blue-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.1.1 running Node.js 20"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# Green Environment
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "green-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.1.1 running Node.js 20"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}
