  region = "us-east-1"
}

# 1. Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# 2. RDS Database Instance
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  db_name              = "myapp_db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = "securepassword123" # Use a secret manager in production
  parameter_group_name = "default.postgres15"
  skip_final_snapshot  = true
}

# 3. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-application"
  description = "Application for myenv"
}

# 4. Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "env" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "eb_ec2_profile1"
  }

  # Connection to RDS
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_URL"
    value     = aws_db_instance.default.endpoint
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = aws_db_instance.default.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.default.password
  }
}

# 5. Route 53 Alias Record pointing to Elastic Beanstalk
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.env.cname
    zone_id                = "Z117K3G2G6ARBC" # This is the Hosted Zone ID for EB in us-east-1
    evaluate_target_health = true
  }
}
