  name                = "my-terraform-env"
  application         = aws_elastic_beanstalk_application.tform_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.2 running Python 3.11"

  # Setting for Instance Profile (IAM Role for EC2)
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.beanstalk_ec2_profile.name
  }

  # Setting for Instance Type
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  # Setting for VPC (Default VPC is assumed here, but can be customized)
  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default.ids)
  }
}

