  solution_stack_name = "64bit Amazon Linux 2023 v4.1.2 running Go 1" # Targets the latest Go stack

  # IAM Instance Profile (Required)
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  # Network configuration (Modify based on your VPC requirements)
  setting {
    namespace = "aws:ec2:vpc"
    name      = "AssociatePublicIpAddress"
    value     = "true"
  }

  # Instance Type
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  # Environment Variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "GIN_MODE"
    value     = "release"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "PORT"
    value     = "8080"
  }
}

# 3. Create IAM Roles and Profiles for the EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb-go-app-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

# Attach standard Beanstalk policies to the role
resource "aws_iam_role_policy_attachment" "web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "worker_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "multicontainer_docker" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "eb-go-app-instance-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Outputs
output "eb_environment_url" {
  value       = aws_elastic_beanstalk_environment.go_env.cname
  description = "The URL of the Elastic Beanstalk Go environment"
}
```

extracted_code:
# Terraform configuration to deploy an AWS App Runner service
# App Runner is a fully managed service that provides autoscaling and 
# automatic deployment for web applications.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Define the Auto Scaling Configuration
resource "aws_apprunner_auto_scaling_configuration_version" "example" {
  auto_scaling_configuration_name = "example-scaling-config"

  # Define scaling thresholds
  max_concurrency = 100
  max_size        = 10
  min_size        = 1

  tags = {
    Name = "app-runner-scaling-config"
  }
}

# IAM Role for App Runner to access other AWS services (if needed)
resource "aws_iam_role" "app_runner_instance_role" {
  name = "app-runner-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "tasks.apprunner.amazonaws.com"
        }
      },
    ]
  })
}

# The App Runner Service using a code repository (e.g., GitHub)
# Note: For GitHub, a Connection Arn is required via the AWS Console/CLI manually first.
resource "aws_apprunner_service" "web_app" {
  service_name = "managed-web-app"

  auto_scaling_configuration_arn = aws_apprunner_auto_scaling_configuration_version.example.arn

  source_configuration {
    # Option 1: Using a Code Repository (Python, Node.js, Go, PHP, Ruby, etc.)
    code_repository {
      repository_url = "https://github.com/example/my-web-app"
      source_code_version {
        type  = "BRANCH"
        value = "main"
      }
      code_configuration {
        configuration_source = "API" # Explicitly defined here rather than apprunner.yaml
        code_configuration_values {
          runtime       = "PYTHON_3" # Or NODEJS_18, GO_1, etc.
          build_command = "pip install -r requirements.txt"
          start_command = "python app.py"
          port          = "8080"
        }
      }
    }

    # Continuous deployment setting
    auto_deployments_enabled = true
  }

  instance_configuration {
    cpu    = "1024"
    memory = "2048"
    instance_role_arn = aws_iam_role.app_runner_instance_role.arn
  }

  tags = {
    Environment = "production"
  }
}

output "app_runner_url" {
  value       = aws_apprunner_service.web_app.service_url
  description = "The URL to access the web application."
}

