# Terraform configuration for an AWS CodeBuild Project with IAM, GitHub Source, and Cache

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CloudWatch Logs and S3 access
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# S3 Bucket for caching and artifacts
resource "aws_s3_bucket" "codebuild_assets" {
  bucket = "my-codebuild-assets-bucket"
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "my-github-project"
  description   = "Sample CodeBuild project with GitHub source"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type           = "S3"
    location       = aws_s3_bucket.codebuild_assets.bucket
    packaging      = "ZIP"
    namespace_type = "BUILD_ID"
    name           = "build-output"
  }

  cache {
    type     = "S3"
    location = "${aws_s3_bucket.codebuild_assets.bucket}/cache"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_FLAVOR"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/my-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "log-group"
      stream_name = "log-stream"
    }
  }

  tags = {
    Environment = "Dev"
  }
}

