# Terraform configuration for AWS CodeBuild Project with IAM Role and Secondary Artifacts

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for S3 and CloudWatch Logs
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

# S3 Bucket for Artifacts
resource "aws_s3_bucket" "artifacts" {
  bucket = "my-codebuild-artifacts-bucket-unique-12345"
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Terraform managed CodeBuild project with secondary artifacts"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifacts.bucket
    name = "primary-artifact"
    packaging = "ZIP"
  }

  # Secondary Artifacts definition
  secondary_artifacts {
    artifact_identifier = "binaries"
    type                = "S3"
    location            = aws_s3_bucket.artifacts.bucket
    path                = "builds/binaries"
    name                = "app-binaries.zip"
  }

  secondary_artifacts {
    artifact_identifier = "docs"
    type                = "S3"
    location            = aws_s3_bucket.artifacts.bucket
    path                = "builds/docs"
    name                = "documentation.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/repo.git"
    git_clone_depth = 1

    # Note: Requires a buildspec.yml in the repo or defined inline here
    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Building..."
            - mkdir dist docs
            - touch dist/app.exe docs/index.html
      artifacts:
        files:
          - '**/*'
        secondary-artifacts:
          binaries:
            files:
              - 'dist/*'
            discard-paths: yes
          docs:
            files:
              - 'docs/*'
            discard-paths: yes
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

