# Terraform Configuration for AWS CodeBuild Project with Multiple Sources and Artifacts

provider "aws" {
  region = "us-east-1"
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Inline policy for CodeBuild permissions (Logs, S3, CodeCommit)
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  name = "codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = ["*"]
      },
      {
        Effect   = "Allow"
        Action   = [
          "codecommit:GitPull"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# AWS CodeBuild Project
resource "aws_codebuild_project" "multi_source_project" {
  name          = "multi-source-build-project"
  description   = "CodeBuild project with multiple sources and artifacts"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  secondary_artifacts {
    artifact_identifier = "artifact_1"
    type                = "S3"
    location            = "my-build-artifacts-bucket"
    path                = "build_output/"
    namespace_type      = "BUILD_ID"
    packaging           = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "artifact_2"
    type                = "S3"
    location            = "my-secondary-artifacts-bucket"
    path                = "backups/"
    packaging           = "NONE"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TARGET"
      value = "production"
    }

    environment_variable {
      name  = "DEBUG_MODE"
      value = "false"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/user/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  secondary_sources {
    source_identifier = "source_repo_2"
    type              = "GITHUB"
    location          = "https://github.com/user/secondary-repo.git"
    git_clone_depth   = 1
  }

