# Terraform configuration to create an AWS Lex V2 Bot with a custom Slot Type and Intent

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex Bot to allow cloudwatch logging
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-v2-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Main Lex Bot
resource "aws_lexv2models_bot" "order_bot" {
  name                        = "OrderPizzaBot"
  description                 = "A bot to handle pizza orders"
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_bot_role.arn
}

# 3. Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.order_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# 4. Custom Slot Type (Pizza Crust)
resource "aws_lexv2models_slot_type" "crust_type" {
  bot_id      = aws_lexv2models_bot.order_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "CrustType"
  description = "Types of pizza crust available"

  slot_type_values {
    sample_value { value = "Thin" }
  }
  slot_type_values {
    sample_value { value = "Thick" }
  }
  slot_type_values {
    sample_value { value = "Stuffed" }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# 5. Intent (OrderPizza)
resource "aws_lexv2models_intent" "order_pizza_intent" {
  bot_id      = aws_lexv2models_bot.order_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I would like to order a pizza" }
  sample_utterance { utterance = "Can I get a {Crust} pizza" }

  fulfillment_code_hook {
    enabled = false
  }
}

# 6. Slot 1: Pizza Size (Built-in Type)
resource "aws_lexv2models_slot" "size_slot" {
  bot_id      = aws_lexv2models_bot.order_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza_intent.intent_id

  name        = "Size"
  slot_type_id = "AMAZON.AlphaNumeric" # Using a built-in type example

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? (Small, Medium, Large)"
          }
        }
      }
    }
  }
}

# 7. Slot 2: Crust (Custom Type created above)
resource "aws_lexv2models_slot" "crust_slot" {
  bot_id       = aws_lexv2models_bot.order_bot.id
  bot_version  = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id    = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id    = aws_lexv2models_intent.order_pizza_intent.intent_id

  name         = "Crust"
  slot_type_id = aws_lexv2models_slot_type.crust_type.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What kind of crust do you want?"
          }
        }
      }
    }
  }
}

# 8. Slot 3: Toppings (Built-in Multi-value)
resource "aws_lexv2models_slot" "toppings_slot" {
  bot_id       = aws_lexv2models_bot.order_bot.id
  bot_version  = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id    = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id    = aws_lexv2models_intent.order_pizza_intent.intent_id

  name         = "Toppings"
  slot_type_id = "AMAZON.AlphaNumeric"

  multiple_values_setting {
    allow_multiple_values = true
  }

  value_elicitation_setting {
    slot_constraint = "Optional"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "Any extra toppings?"
          }
        }
      }
    }
  }
}

