}

# Slot Type: Pizza Size
resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaSize"

  slot_type_values {
    sample_value { value = "small" }
  }
  slot_type_values {
    sample_value { value = "medium" }
  }
  slot_type_values {
    sample_value { value = "large" }
  }
}

# Intent: Order Pizza
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I would like to order a pizza" }
  sample_utterance { utterance = "Can I get a {size} pizza" }

  # Slot for Pizza Size
  slot {
    name        = "size"
    slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id
    value_elicitation_setting {
      prompt_specification {
        max_retries = 2
        message_group {
          message {
            plain_text_message {
              value = "What size pizza would you like? (small, medium, or large)"
            }
          }
        }
      }
      slot_constraint = "Required"
    }
  }

  # Confirmation and Follow-up Prompt Logic
  fulfillment_code_hook {
    enabled = false
  }

  # Closing Response with Follow-up Question
  closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great, I have placed your order for a {size} pizza. Would you like to add a drink to that?"
          }
        }
      }
    }
    active = true
  }
}

