resource "aws_lexv2models_intent" "add_drink" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "AddDrink"

  sample_utterance { utterance = "Yes please" }
  sample_utterance { utterance = "Sure" }
  sample_utterance { utterance = "I want a soda" }

  closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Excellent, we've added a drink to your order. It will be ready in 20 minutes!"
          }
        }
      }
    }
    active = true
  }
}

