# The Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  description                 = "A bot to handle pizza orders"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_bot_role.arn

  data_privacy {
    child_directed = false
  }
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I would like to order a pizza" }
  sample_utterance { utterance = "Can I get a pizza" }
  sample_utterance { utterance = "Order pizza" }

  # Slot: Pizza Size
  slot_priority {
    priority = 1
    slot_name = "PizzaSize"
  }

  # Closing Setting / Summary Statement
  closing_setting {
    active = true
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Thank you! Your pizza order has been placed and will be ready for pickup soon. Enjoy your meal!"
          }
        }
      }
    }
  }
}

# Slot Type: Size
resource "aws_lexv2models_slot_type" "pizza_size_type" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaSize"

  slot_type_values {
    sample_value { value = "small" }
  }
  slot_type_values {
    sample_value { value = "medium" }
  }
  slot_type_values {
    sample_value { value = "large" }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# Slot definition within the Intent
resource "aws_lexv2models_slot" "pizza_size_slot" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id
  name        = "PizzaSize"
  slot_type_id = aws_lexv2models_slot_type.pizza_size_type.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? (Small, Medium, or Large)"
          }
        }
      }
    }
  }
}
