provider "aws" {
  region = "us-east-1"
}

# IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "TripReservationLexBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Main Lex Bot Resource
resource "aws_lex_bot" "trip_reservation_bot" {
  name                         = "TripReservationBot"
  description                  = "Bot for booking trips including hotels and cars"
  process_behavior             = "BUILD"
  locale                       = "en-US"
  child_directed               = false
  create_version               = true
  idle_session_ttl_in_seconds  = 300
  voice_id                     = "Salli"

  # Intent definitions
  intent {
    intent_name    = "BookHotel"
    intent_version = "1"
  }

  intent {
    intent_name    = "BookCar"
    intent_version = "1"
  }

  # Clarification prompt for when the bot doesn't understand
  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand that. Can you please repeat? I can help you book a hotel or a car."
      content_type = "PlainText"
    }
  }

  # Message sent when the bot cannot resolve the intent
  abort_statement {
    message {
      content      = "I'm sorry, I'm not able to assist with that request at this time."
      content_type = "PlainText"
    }
  }
}

# Example Intent: BookHotel
resource "aws_lex_intent" "book_hotel" {
  name        = "BookHotel"
  description = "Intent to book a hotel room"

  sample_utterances = [
    "I would like to book a hotel",
    "Book a hotel in {Location}",
    "I want to make a hotel reservation"
  ]

  # Slot for Location
  slot {
    name              = "Location"
    description       = "The city where the hotel is located"
    slot_constraint   = "Required"
    slot_type         = "AMAZON.US_CITY"
    priority          = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "Which city will you be staying in?"
        content_type = "PlainText"
      }
    }
  }

  # Slot for Check-in Date
  slot {
    name              = "CheckInDate"
    description       = "The date of check-in"
    slot_constraint   = "Required"
    slot_type         = "AMAZON.DATE"
    priority          = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day do you want to check in?"
        content_type = "PlainText"
      }
    }
  }

  # Confirmation Prompt
  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I have you down for a stay in {Location} starting {CheckInDate}. Shall I book it?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation request."
      content_type = "PlainText"
    }
  }

  # Fulfillment activity
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Example Intent: BookCar
resource "aws_lex_intent" "book_car" {
  name        = "BookCar"
  description = "Intent to book a rental car"

  sample_utterances = [
    "Book a car",
    "Reserve a rental car",
    "Make a car reservation in {PickUpCity}"
  ]

  slot {
    name              = "PickUpCity"
    description       = "City where the car will be picked up"
    slot_constraint   = "Required"
    slot_type         = "AMAZON.US_CITY"
    priority          = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "In what city do you need to rent a car?"
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

