resource "aws_lexv2models_intent" "store_hours" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "StoreHours"

  sample_utterance { utterance = "What time do you close?" }
  sample_utterance { utterance = "Are you open?" }

  closing_setting {
    closing_response {
      message_group {
