resource "aws_lexv2models_intent" "cancel_order" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "CancelOrder"

  sample_utterance { utterance = "Cancel my order" }
  sample_utterance { utterance = "I want to stop my order" }

  confirmation_setting {
    prompt_specification {
      max_retries = 1
      message_group {
        message {
          plain_text_message {
            value = "Are you sure you want to cancel your order?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "Okay, I will not cancel your order."
          }
        }
      }
    }
  }
}

