# Terraform configuration for an AWS Lex V2 Bot to handle pizza orders for children
# This includes the Bot, Locale (English US), Intents, Slot Types, and proper IAM Role

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# IAM Role for Lex Bot to allow execution
resource "aws_iam_role" "lex_pizza_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# The Lex Bot
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "ChildrensPizzaOrderBot"
  description                 = "A simple pizza ordering bot designed for kids."
  role_arn                    = aws_iam_role.lex_pizza_bot_role.arn
  data_privacy {
    child_directed = true
  }
  idle_session_ttl_in_seconds = 300
}

# English Locale for the Bot
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Custom Slot Type for Pizza Toppings
resource "aws_lexv2models_slot_type" "topping_type" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaToppingType"

  slot_type_values {
    sample_value { value = "Cheese" }
  }
  slot_type_values {
    sample_value { value = "Pepperoni" }
  }
  slot_type_values {
    sample_value { value = "Sausage" }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# Main Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I have a pizza please" }
  sample_utterance { utterance = "I'm hungry for pizza" }

  # Slot 1: Topping
  slot {
    name        = "Topping"
    slot_type_id = aws_lexv2models_slot_type.topping_type.slot_type_id
    value_elicitation_setting {
      prompt_specification {
        max_retries = 2
        message_group {
          message {
            plain_text_message {
              content = "What kind of pizza do you want? We have cheese, pepperoni, or sausage!"
            }
          }
        }
      }
      slot_constraint = "Required"
    }
  }

  # Slot 2: Size
  slot {
    name        = "PizzaSize"
    slot_type_id = "AMAZON.AlphaNumeric" # Using a built-in type for simplicity
    value_elicitation_setting {
      prompt_specification {
        max_retries = 2
        message_group {
          message {
            plain_text_message {
              content = "Should it be a small, medium, or big pizza?"
            }
          }
        }
      }
      slot_constraint = "Required"
    }
  }

  confirmation_setting {
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            content = "Okay! So you want a {PizzaSize} {Topping} pizza, right?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            content = "No problem, we can start over when you are ready."
          }
        }
      }
    }
  }

  fulfillment_code_hook {
    enabled = false # Set to true if linking to a Lambda function
  }
}

# Fallback Intent
resource "aws_lexv2models_intent" "fallback" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}

