# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_bot_lex_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# Define the Lex Bot (V1 API)
resource "aws_lex_bot" "pizza_bot" {
  name                         = "PizzaOrderingBot"
  description                  = "Bot for ordering pizza"
  process_behavior             = "BUILD"
  locale                       = "en-US"
  child_directed               = false
  create_version               = true
  idle_session_ttl_in_seconds  = 300

  # Configure NLU Intent Confidence Threshold
  nlu_intent_confidence_threshold = 0.5

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist with that request at this time."
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I didn't quite catch that. Can you repeat your pizza order?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }
}

# Define the Intent for the Bot
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizzaIntent"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Buy a pizza",
    "Can I get a {PizzaType} pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "The type of pizza"
    priority    = 1
    required    = true
    slot_type   = "AMAZON.AlphaNumeric"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What kind of pizza would you like (e.g., Pepperoni, Cheese)?"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "Okay, I have you down for a {PizzaType} pizza. Should I place the order?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "No problem, the order has been cancelled."
    }
  }
}

