# Terraform Configuration for AWS Lex Bot (V1) - Pizza Order System

provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex to invoke Lambda
resource "aws_iam_role" "lex_lambda_role" {
  name = "lex-pizza-bot-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Lambda Function for Fulfillment
resource "aws_lambda_function" "pizza_fulfillment" {
  function_name    = "pizza_order_fulfillment"
  role             = aws_iam_role.lex_lambda_role.arn
  handler          = "index.handler"
  runtime          = "nodejs18.x"
  filename         = "lambda_function_payload.zip" # Assumes a local zip file exists

  source_code_hash = filebase64sha256("lambda_function_payload.zip")
}

# 3. Permission for Lex to invoke the Lambda
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_fulfillment.function_name
  principal     = "lex.amazonaws.com"
}

# 4. Lex Intent
resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Buy a pizza",
    "Can I get a {PizzaType} pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "The type of pizza (e.g., cheese, pepperoni)"
    priority    = 1
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric" # Or a custom slot type

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What kind of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaSize"
    description = "Size of the pizza"
    priority    = 2
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I have a {PizzaSize} {PizzaType} pizza. Should I place the order?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "No problem, the order has been cancelled."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      message_version = "1.0"
      uri             = aws_lambda_function.pizza_fulfillment.arn
    }
  }
}

# 5. Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name                         = "PizzaOrderBot"
  description                  = "Bot for ordering pizza"
  locale                       = "en-US"
  child_directed               = false
  idle_session_ttl_in_seconds = 300

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }

  abort_statement {
    message {
      content      = "I'm sorry, I'm not able to assist with that right now."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't quite get that. Can you say it again?"
      content_type = "PlainText"
    }
  }

  process_behavior = "BUILD"
  depends_on      = [aws_lambda_permission.allow_lex]
}

