# Terraform configuration for an AWS Lex V2 Bot
# Includes the Bot, Bot Version, Bot Alias, and a Sample Intent

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_role" {
  name = "lex-v2-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Lex Logging and Execution
resource "aws_iam_role_policy_attachment" "lex_exec_policy" {
  role       = aws_iam_role.lex_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# Lex V2 Bot
resource "aws_lexv2models_bot" "example" {
  name                        = "OrderFlowersBot"
  description                 = "A bot to help users order flowers"
  role_arn                    = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300

  tags = {
    Environment = "Development"
  }
}

# Lex V2 Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.example.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold  = 0.40
}

# Lex V2 Intent (Sample: OrderFlowers)
resource "aws_lexv2models_intent" "order_flowers" {
  bot_id      = aws_lexv2models_bot.example.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderFlowers"

  sample_utterance {
    utterance = "I would like to order flowers"
  }
  sample_utterance {
    utterance = "Can I buy some flowers?"
  }

  initial_response_setting {
    next_step {
      dialog_action {
        type = "ConfirmIntent"
      }
    }
  }
}

# Lex V2 Bot Version
resource "aws_lexv2models_bot_version" "example" {
  bot_id      = aws_lexv2models_bot.example.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [aws_lexv2models_intent.order_flowers]
}

# Lex V2 Bot Alias
resource "aws_lexv2models_bot_alias" "prod" {
  name        = "Production"
  bot_id      = aws_lexv2models_bot.example.id
  bot_version = aws_lexv2models_bot_version.example.bot_version

  sentiment_analysis_settings {
    detect_sentiment = true
  }

  conversation_log_settings {
    # Logging configuration can be added here (CloudWatch/S3)
  }
}

