# IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-kids-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# Lex V2 Bot optimized for kids (COPPA Compliant configuration)
resource "aws_lexv2models_bot" "kids_bot" {
  name                        = "FriendlyKidsBot"
  description                 = "A safe and educational bot designed specifically for children."
  role_arn                    = aws_iam_role.lex_bot_role.arn
  idle_session_ttl_in_seconds = 300

  # COPPA Compliance: This is the critical setting for bots intended for kids
  data_privacy {
    child_directed = true
  }

  # Initial version configuration
  members {
    # If using multiple bots in a network, they would be defined here
  }
}

# Locale configuration (English - US)
resource "aws_lexv2models_bot_locale" "kids_bot_en_us" {
  bot_id                           = aws_lexv2models_bot.kids_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.70

  voice_settings {
    # Using 'Ivy' - a child-like/youthful voice from Amazon Polly
    voice_id = "Ivy"
    engine   = "neural"
  }
}

# Example Intent: Greeting
resource "aws_lexv2models_intent" "greeting_intent" {
  bot_id      = aws_lexv2models_bot.kids_bot.id
  bot_version = aws_lexv2models_bot_locale.kids_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.kids_bot_en_us.locale_id
  name        = "HelloIntent"

  sample_utterance { utterance = "Hi bot" }
  sample_utterance { utterance = "Hello" }
  sample_utterance { utterance = "Can we play?" }

  initial_response_setting {
    code_hook {
      active = false
    }

    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Hi there! I am your friendly robot friend. What would you like to learn today?"
          }
        }
      }
    }
  }
}

# Fallback Intent to handle misunderstood phrases gently
resource "aws_lexv2models_intent" "fallback_intent" {
  bot_id      = aws_lexv2models_bot.kids_bot.id
  bot_version = aws_lexv2models_bot_locale.kids_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.kids_bot_en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"

  initial_response_setting {
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "I'm sorry, I didn't quite catch that. Could you say it again in a different way?"
          }
        }
      }
    }
  }
}

