# Terraform configuration to associate a Lex (V1) Bot with an Amazon Connect Instance

# Standard provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Provide the Amazon Connect Instance ID
# Replace this with your actual instance ID or a reference to an aws_connect_instance resource
variable "connect_instance_id" {
  type    = string
  default = "your-instance-uuid-here"
}

# 2. Reference or define the Lex Bot
# Note: For V1 bots, the name is used. For V2 bots, use aws_connect_lambda_function_association 
# or specific V2 resources if supported by your provider version.
resource "aws_lex_bot" "kids_helper_bot" {
  name                         = "KidsHelperBot"
  child_directed               = true
  create_version               = true
  description                  = "A friendly bot designed for children's queries."
  idle_session_ttl_in_seconds  = 300
  locale                       = "en-US"

  # Note: A placeholder intent is required for a valid bot configuration
  intent {
    intent_name    = "OrderToyIntent"
    intent_version = "1"
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I didn't quite catch that. Can you say it again?"
    }
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "I'm having a little trouble understanding. Let me get someone to help you."
    }
  }
}

# 3. Create the Association
# This allows the Connect Instance to use the Lex Bot in its Contact Flows
resource "aws_connect_bot_association" "example" {
  instance_id = var.connect_instance_id

  lex_bot {
    name     = aws_lex_bot.kids_helper_bot.name
    lex_region = "us-east-1"
  }
}

