# Terraform configuration to create an AWS Connect Bot Association
# for an instance using SAML authentication.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. AWS Connect Instance with SAML identity management
resource "aws_connect_instance" "example" {
  identity_management_type = "SAML"
  inbound_calls_enabled    = true
  outbound_calls_enabled   = true
  instance_alias           = "my-saml-connect-instance"
}

# 2. Lex V1 Bot (Classic)
# Note: Connect Bot Association supports Lex V1 and V2. 
# This example uses a Reference to a Lex V1 bot.
resource "aws_lex_bot" "example" {
  name        = "OrderFlowers"
  description = "Example Lex V1 bot for Connect"

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time."
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = "OrderFlowers"
    intent_version = "1"
  }

  child_directed      = false
  locale              = "en-US"
  process_behavior    = "SAVE"
}

# 3. Associate the Bot with the Connect Instance
resource "aws_connect_bot_association" "example" {
  instance_id = aws_connect_instance.example.id

  lex_bot {
    name = aws_lex_bot.example.name
    # The region where the Lex bot resides
    lex_region = "us-east-1"
  }
}

# Output the Instance ID for verification
output "connect_instance_id" {
  value = aws_connect_instance.example.id
}

