extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Kinesis Data Stream (Input Source)
resource "aws_kinesis_stream" "input_stream" {
  name        = "example-input-stream"
  shard_count = 1
}

# 2. IAM Role for Kinesis Analytics
resource "aws_iam_role" "analytics_role" {
  name = "example-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      },
    ]
  })
}

# 3. IAM Policy for the Role to read from Kinesis
resource "aws_iam_role_policy" "analytics_policy" {
  name = "example-analytics-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream"
        ]
        Effect   = "Allow"
        Resource = [aws_kinesis_stream.input_stream.arn]
      }
    ]
  })
}

# 4. Kinesis Data Analytics Application (SQL-based)
resource "aws_kinesis_analytics_application" "example_app" {
  name = "example-sql-analytics-app"

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        name     = "sector"
        sql_type = "VARCHAR(64)"
        mapping  = "$.sector"
      }
      record_columns {
        name     = "price"
        sql_type = "DOUBLE"
        mapping  = "$.price"
      }
      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  code = <<EOF
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sector VARCHAR(64), total_price DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM sector, SUM(price) OVER (
  PARTITION BY sector
  RANGE INTERVAL '10' SECOND PRECEDING) AS total_price
FROM "SOURCE_SQL_STREAM_001";
EOF
}

