provider "aws" {
  region = "us-east-1"
}

# S3 Bucket to store the Flink application code (JAR file)
resource "aws_s3_bucket" "flink_assets" {
  bucket_prefix = "kinesis-analytics-binaries-"
  force_destroy = true
}

# Example S3 object representing the Flink Application jar
resource "aws_s3_object" "flink_app_jar" {
  bucket = aws_s3_bucket.flink_assets.id
  key    = "flink-app-v1.jar"
  source = "path/to/your/flink/application.jar" # Path to your local JAR file
}

# IAM Role for Kinesis Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-flink-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy to allow reading from S3
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-flink-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.flink_assets.arn,
          "${aws_s3_bucket.flink_assets.arn}/*"
        ]
      },
      {
        Action = [
            "logs:PutLogEvents",
            "logs:CreateLogStream",
            "logs:DescribeLogGroups",
            "logs:DescribeLogStreams"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for Flink application logs
resource "aws_cloudwatch_log_group" "flink_log_group" {
  name = "/aws/kinesis-analytics/my-flink-app"
}

resource "aws_cloudwatch_log_stream" "flink_log_stream" {
  name           = "flink-log-stream"
  log_group_name = aws_cloudwatch_log_group.flink_log_group.name
}

# Kinesis Data Analytics V2 Application (Managed Apache Flink)
resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "my-flink-application"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.flink_assets.arn
          file_key   = aws_s3_object.flink_app_jar.key
        }
      }
      code_content_type = "ZIPFILE"
    }

    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 1
        parallelism_per_kpu  = 1
      }
    }

    application_snapshot_configuration {
      snapshots_enabled = false
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.flink_log_stream.arn
  }
}

