# Terraform configuration for Kinesis Data Firehose with Dynamic Partitioning and S3 Destination

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for Firehose destination
resource "aws_s3_bucket" "destination" {
  bucket = "firehose-dynamic-partitioning-demo-bucket"
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Firehose to access S3
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = civic_amazon_kinesis_firehose_delivery_stream.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.destination.arn,
          "${aws_s3_bucket.destination.arn}/*"
        ]
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream with Dynamic Partitioning
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "dynamic-partitioning-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.destination.arn

    # Custom prefix using partition keys defined in dynamic_partitioning_configuration
    # Example assumes the record has a "customer_id" field
    prefix              = "data/customer_id=!{partitionKeyFromQuery:customer_id}/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_output_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/!{firehose:error-output-type}/"

    # Dynamic Partitioning Configuration
    dynamic_partitioning_configuration {
      enabled = true
    }

    # Inline parsing of JSON to extract partition keys
    processing_configuration {
      enabled = true

      # Metadata extraction from JSON record
      processors {
        type = "MetadataExtraction"
        parameters {
          parameter_name  = "MetadataExtractionQuery"
          parameter_value = "{customer_id: .customer_id}"
        }
        parameters {
          parameter_name  = "JsonParsingEngine"
          parameter_value = "JQ-1.6"
        }
      }

      # Append newlines between records (optional but recommended for many downstream tools)
      processors {
        type = "AppendDelimiterToRecord"
      }
    }

    # Buffer settings
    buffering_size     = 64
    buffering_interval = 60
  }
}

