  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

# --- S3 Intermediate Bucket (Required for Firehose-Redshift) ---
resource "aws_s3_bucket" "firehose_bucket" {
  bucket_prefix = "firehose-redshift-temp-"
}

# --- Redshift Cluster ---
resource "aws_redshift_cluster" "main" {
  cluster_identifier  = "tf-redshift-cluster"
  database_name       = "dev"
  master_username     = "adminuser"
  master_password     = "MustBeComplex123!"
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  skip_final_snapshot = true
}

# --- IAM Roles and Policies ---
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_redshift_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "firehose.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_redshift_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Action = [
          "redshift:DescribeClusters",
          "redshift:PauseCluster",
          "redshift:ResumeCluster"
        ]
        Effect   = "Allow"
        Resource = [aws_redshift_cluster.main.arn]
      }
    ]
  })
}

# --- Kinesis Data Firehose Delivery Stream ---
