# Terraform configuration to create a Kinesis Data Firehose delivery stream to Splunk

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for failed events (Backup)
resource "aws_s3_bucket" "splunk_backup" {
  bucket = "my-splunk-firehose-backup-bucket"
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_splunk_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Firehose to access S3 and CloudWatch
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_splunk_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.splunk_backup.arn,
          "${aws_s3_bucket.splunk_backup.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = ["*"]
      }
    ]
  })
}

# Kinesis Data Firehose Delivery Stream to Splunk
resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name        = "terraform-splunk-delivery-stream"
  destination = "splunk"

  splunk_configuration {
    hec_endpoint               = "https://splunk-hec.example.com:8088"
    hec_token                  = "00000000-0000-0000-0000-000000000000"
    hec_acknowledgment_timeout = 600
    hec_endpoint_type         = "Raw"
    retry_duration            = 300

    s3_backup_mode = "FailedEventsOnly"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.splunk_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    # Optional: CloudWatch Logging
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/splunk-stream"
      log_stream_name = "SplunkDelivery"
    }
  }
}

