  name        = "terraform-splunk-delivery-stream"
  destination = "splunk"

  splunk_configuration {
    hec_endpoint               = "https://splunk-hec.example.com:8088"
    hec_token                  = "00000000-0000-0000-0000-000000000000"
    hec_acknowledgment_timeout = 600
    hec_endpoint_type         = "Raw"
    retry_duration            = 300

    s3_backup_mode = "FailedEventsOnly"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.splunk_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    # Optional: CloudWatch Logging
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/splunk-stream"
      log_stream_name = "SplunkDelivery"
    }
  }
}
