# Terraform configuration for Kinesis Data Firehose with OpenSearch Serverless destination

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Firehose backup (Required)
resource "aws_s3_bucket" "firehose_backup" {
  bucket_prefix = "firehose-opensearch-backup-"
}

# 2. OpenSearch Serverless Collection
resource "aws_opensearchserverless_collection" "this" {
  name = "firehose-collection"
  type = "SEARCH"
}

# 3. OpenSearch Serverless Security Policies
resource "aws_opensearchserverless_access_policy" "this" {
  name        = "firehose-access-policy"
  type        = "data"
  description = "Allow Firehose to write to the collection"
  policy      = jsonencode([
    {
      Rules = [
        {
          ResourceType = "index",
          Resource     = ["index/${aws_opensearchserverless_collection.this.name}/*"],
          Permission   = ["indices:CreateIndex", "indices:Write", "indices:DescribeIndex"]
        },
        {
          ResourceType = "collection",
          Resource     = ["collection/${aws_opensearchserverless_collection.this.name}"],
          Permission   = ["aoss:CreateCollectionItems"]
        }
      ],
      Principal = [aws_iam_role.firehose_role.arn]
    }
  ])
}

# 4. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_opensearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["s3:AbortMultipartUpload", "s3:GetBucketLocation", "s3:GetObject", "s3:ListBucket", "s3:ListBucketMultipartUploads", "s3:PutObject"]
        Resource = [aws_s3_bucket.firehose_backup.arn, "${aws_s3_bucket.firehose_backup.arn}/*"]
      },
      {
        Effect   = "Allow"
        Action   = ["aoss:APIAccessAll"]
        Resource = [aws_opensearchserverless_collection.this.arn]
      }
    ]
  })
}

# 5. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "this" {
  name        = "opensearch-serverless-delivery-stream"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_endpoint = aws_opensearchserverless_collection.this.collection_endpoint
    index_name          = "logs"
    role_arn            = aws_iam_role.firehose_role.arn

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled         = false
    }
  }
}

