resource "aws_kinesis_firehose_delivery_stream" "es_delivery_stream" {
  name        = "terraform-kinesis-firehose-es-stream"
  destination = "elasticsearch"

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "GZIP"
  }

  elasticsearch_configuration {
    domain_arn     = "arn:aws:es:us-east-1:123456789012:domain/my-vpc-domain" # Replace with actual Domain ARN
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "logs"
    type_name      = "_doc"
    index_rotation_period = "NoRotation"

    vpc_config {
      subnet_ids         = ["subnet-xxxxxxxxxxxxxxxxx"] # Replace with VPC Subnet ID
      security_group_ids = ["sg-xxxxxxxxxxxxxxxxx"]     # Replace with Security Group ID
      role_arn           = aws_iam_role.firehose_role.arn
    }

    s3_backup_mode = "FailedDocumentsOnly"
  }
}

# IAM Policy to allow Firehose to interact with ES, S3, and VPC
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_es_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = ["arn:aws:es:us-east-1:123456789012:domain/my-vpc-domain/*"]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = ["*"]
      }
    ]
  })
}
