    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for failed data delivery (required for Firehose)
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-http-backup-bucket-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_http_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy to allow Firehose to write to S3 and Log to CloudWatch
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = ["*"]
      }
    ]
  })
}

# CloudWatch Log Group for monitoring
resource "aws_cloudwatch_log_group" "firehose_logs" {
  name = "/aws/kinesisfirehose/http-delivery-stream"
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "HttpDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose_logs.name
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "http_stream" {
  name        = "firehose-to-http-endpoint"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url                = "https://aws-api.newrelic.com/firehose/v1" # Replace with actual New Relic endpoint
    name               = "New Relic"
    access_key         = "YOUR_NEW_RELIC_INSERT_KEY" # It is recommended to use sensitive variables or Secrets Manager
    retry_duration     = 300
    role_arn           = aws_iam_role.firehose_role.arn
    buffering_size     = 5
    buffering_interval = 60

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }

    # S3 backup configuration for failed records
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    request_configuration {
      common_attributes {
        name  = "LogSource"
        value = "KinesisFirehose"
      }
    }
  }
}

