extracted_code:
# Terraform configuration for a simple Amazon Kinesis Data Analytics Application (SQL-based)
# This includes the application itself along with a Kinesis Data Stream as the source.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a Kinesis Data Stream to serve as the input source
resource "aws_kinesis_stream" "input_stream" {
  name             = "analytics-input-stream"
  shard_count      = 1
  retention_period = 24
}

# 2. IAM Role for the Kinesis Analytics Application
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "kinesisanalytics.amazonaws.com"
      }
    }]
  })
}

# 3. IAM Policy to allow the application to read from the stream
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-policy"
  role = "kinesis-analytics-role"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.input_stream.arn
      }
    ]
  })
}

# 4. Kinesis Data Analytics Application
resource "aws_kinesis_analytics_application" "sql_app" {
  name = "simple-sql-analytics-app"

  # Basic SQL code that copies data from input to an in-application output stream
  code = <<EOT
    CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
        ticker_symbol VARCHAR(4),
        sector        VARCHAR(12),
        price         DOUBLE
    );

    CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
    INSERT INTO "DESTINATION_SQL_STREAM"
    SELECT STREAM ticker_symbol, sector, price
    FROM "SOURCE_SQL_STREAM_001";
  EOT

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        name     = "ticker_symbol"
        mapping  = "$.ticker_symbol"
        sql_type = "VARCHAR(4)"
      }
      record_columns {
        name     = "sector"
        mapping  = "$.sector"
        sql_type = "VARCHAR(12)"
      }
      record_columns {
        name     = "price"
        mapping  = "$.price"
        sql_type = "DOUBLE"
      }

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }
}

output "application_arn" {
  value       = aws_kinesis_analytics_application.sql_app.arn
  description = "The ARN of the Kinesis Data Analytics Application"
}

