# Terraform configuration for an Amazon Kinesis Data Analytics V2 SQL Application

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Provide an S3 Bucket for application code/logs
resource "aws_s3_bucket" "analytics_assets" {
  bucket_prefix = "kinesis-analytics-assets-"
}

# 2. IAM Role for Kinesis Data Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-sql-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "kinesisanalytics.amazonaws.com"
      }
    }]
  })
}

# 3. Kinesis Data Stream (Input Source)
resource "aws_kinesis_stream" "input_stream" {
  name         = "input-data-stream"
  shard_count = 1
}

# 4. Kinesis Data Analytics V2 Application (SQL Based)
resource "aws_kinesisanalyticsv2_application" "sql_app" {
  name                   = "my-sql-analytics-app"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_template = "$"
              }
            }
          }

          record_column {
            name     = "sensor_id"
            sql_type = "VARCHAR(64)"
            mapping  = "$.sensor_id"
          }

          record_column {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temp"
          }
        }

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
        }
      }
    }

    application_code_configuration {
      code_content {
        text_content = <<EOF
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sensor_id VARCHAR(64), avg_temp DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM "sensor_id", AVG("temperature") OVER (
  RANGE INTERVAL '10' SECOND PRECEDING) AS avg_temp
FROM "SOURCE_SQL_STREAM_001";
EOF
      }
      code_content_type = "PLAINTEXT"
    }
  }

  tags = {
    Environment = "Dev"
  }
}
```

