# Terraform configuration for AWS Kinesis Data Analytics with CloudWatch Logging
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. CloudWatch Log Group and Stream for the Application
resource "aws_cloudwatch_log_group" "analytics_logs" {
  name              = "/aws/kinesis-analytics/my-application"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "analytics_stream" {
  name           = "kinesis-analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.analytics_logs.name
}

# 2. IAM Role for Kinesis Analytics
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "kinesisanalytics.amazonaws.com"
      }
    }]
  })
}

# 3. IAM Policy to allow writing to CloudWatch Logs
resource "aws_iam_role_policy" "analytics_logging_policy" {
  name   = "kinesis-analytics-logging-policy"
  role   = aws_iam_role.analytics_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:PutLogEvents",
          "logs:DescribeLogStreams",
          "logs:DescribeLogGroups"
        ]
        Effect   = "Allow"
        Resource = "${aws_cloudwatch_log_group.analytics_logs.arn}:*"
      }
    ]
  })
}

# 4. Kinesis Data Analytics SQL Application
resource "aws_kinesis_analytics_application" "example_app" {
  name = "my-kinesis-analytics-app"
  code = "CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (ticker_symbol VARCHAR(4), sector VARCHAR(16), change DOUBLE, price DOUBLE);"

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.analytics_stream.arn
    role_arn       = aws_iam_role.analytics_role.arn
  }

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        name     = "ticker_symbol"
        mapping  = "$.ticker_symbol"
        sql_type = "VARCHAR(4)"
      }
      record_columns {
        name     = "sector"
        mapping  = "$.sector"
        sql_type = "VARCHAR(16)"
      }
      record_columns {
        name     = "change"
        mapping  = "$.change"
        sql_type = "DOUBLE"
      }
      record_columns {
        name     = "price"
        mapping  = "$.price"
        sql_type = "DOUBLE"
      }
      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }
}

# 5. Input Kinesis Stream (Data Source)
resource "aws_kinesis_stream" "input_stream" {
  name        = "input-data-stream"
  shard_count = 1
}

