# Terraform configuration to create an Amazon Kendra Index and a Data Source with Proxy Settings.
# This example uses a Web Crawler data source as it commonly requires proxy configurations.

resource "aws_iam_role" "kendra_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"
}

resource "aws_kendra_data_source" "example_web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler-with-proxy"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = ["https://example.com"]
        }
      }

      # Proxy configuration is defined here
      proxy_configuration {
        host = "proxy.example.com"
        port = 8080
        # Optional: credentials if the proxy requires authentication
        # credentials = aws_secretsmanager_secret.proxy_auth.arn
      }
    }
  }
}

