# Terraform configuration to create an AWS Kendra Web Crawler Data Source
# with specific URL inclusion and exclusion patterns.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_kendra_index" "example" {
  name     = "example-kendra-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"
}

resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler-datasource"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = ["https://aws.amazon.com"]
          web_crawler_mode = "EVERYTHING"
        }
      }

      # URL Inclusion and Exclusion Patterns
      # Note: Patterns use Java Regular Expression syntax
      url_inclusion_patterns = [
        "https://aws.amazon.com/blogs/.*",
        "https://aws.amazon.com/whitepapers/.*"
      ]

      url_exclusion_patterns = [
        ".*\.pdf",
        "https://aws.amazon.com/blogs/tags/.*"
      ]
    }
  }
}

resource "aws_iam_role" "kendra_role" {
  name = "kendra-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-example-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["kendra:BatchPutDocument", "kendra:BatchDeleteDocument"]
        Resource = aws_kendra_index.example.arn
      },
      {
        Effect   = "Allow"
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Resource = "*"
      }
    ]
  })
}

