# Terraform configuration for AWS Kendra Index with Metadata Configuration

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "kendra_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"

  document_metadata_configuration_updates {
    name = "ProjectName"
    type = "STRING_VALUE"
    search {
      displayable = true
      facetable   = true
      searchable  = true
      sortable    = true
    }
  }

  document_metadata_configuration_updates {
    name = "DocumentVersion"
    type = "NUMBER_VALUE"
    search {
      displayable = true
      facetable   = false
      searchable  = false
      sortable    = true
    }
  }

  tags = {
    Environment = "Development"
  }
}
```

