# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for Amazon Kendra
resource "aws_iam_role" "kendra_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Basic policy for Kendra to log to CloudWatch
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Resource = "*"
      }
    ]
  })
}

# AWS Kendra Index with User Group Resolution
resource "aws_kendra_index" "example" {
  name     = "example-kendra-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"

  # User Group Resolution configuration
