variable "domain_name" {
  description = "The root domain name for the hosted zone"
  type        = string
}

variable "primary_endpoint_fqdn" {
  description = "The FQDN for the primary resource health check"
  type        = string
}

variable "primary_ip" {
  description = "IP address of the primary resource"
  type        = string
}

variable "secondary_ip" {
  description = "IP address of the secondary (passive) resource"
  type        = string
}

resource "aws_route53_zone" "primary" {
  name = var.domain_name
}

resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = var.primary_endpoint_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Name = "primary-health-check"
  }
}

resource "aws_route53_record" "primary_failover" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.${var.domain_name}"
  type    = "A"
  ttl     = "60"

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier  = "primary-record"
  health_check_id = aws_route53_health_check.primary_health_check.id
  records         = [var.primary_ip]
}

resource "aws_route53_record" "secondary_failover" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.${var.domain_name}"
  type    = "A"
  ttl     = "60"

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier = "secondary-record"
  records        = [var.secondary_ip]
}

