# Terraform configuration for Route 53 Traffic Policy with Geoproximity/Weighted routing
# to simulate load-based direction across us-east-1 and eu-central-1.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Fetch the existing hosted zone named "primary"
data "aws_route53_zone" "primary" {
  name         = "primary."
  private_zone = false
}

# Define the Traffic Policy
# This policy uses a Geoproximity rule to route users to the nearest healthy endpoint,
# effectively distributing load across regions geographically.
resource "aws_route53_traffic_policy" "load_distribution_policy" {
  name     = "load-distribution-policy"
  comment  = "Directs traffic to endpoints in us-east-1 and eu-central-1 with optimized routing"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    StartRule              = "geoproximity_rule"
    Endpoints = {
      usa_endpoint = {
        Type   = "value"
        Value  = "us-east-1-elb.example.com"
      }
      eu_endpoint = {
        Type   = "value"
        Value  = "eu-central-1-elb.example.com"
      }
    }
    Rules = {
      geoproximity_rule = {
        RuleType = "Geoproximity"
        GeoproximityLocations = [
          {
            Region    = "us-east-1"
            Bias      = 0
            EndpointReference = "usa_endpoint"
          },
          {
            Region    = "eu-central-1"
            Bias      = 0
            EndpointReference = "eu_endpoint"
          }
        ]
      }
    }
  })
}

# Create a Traffic Policy Instance to apply the policy to the hosted zone
resource "aws_route53_traffic_policy_instance" "primary_instance" {
  name                   = "service.primary"
  traffic_policy_id      = aws_route53_traffic_policy.load_distribution_policy.id
  traffic_policy_version = aws_route53_traffic_policy.load_distribution_policy.version
  hosted_zone_id         = data.aws_route53_zone.primary.zone_id
  ttl                    = 300
}

