resource "aws_route53_traffic_policy" "geo_policy" {
  name     = "geo-location-policy"
  comment  = "Directs users to closest endpoint based on continent (US and EU)"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    StartRule              = "geoproximity_rule"
    Endpoints = {
      us_endpoint = {
