# Terraform configuration for an Amazon Route 53 Traffic Policy and Instance

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Define the Route 53 Traffic Policy using a JSON document
# This example implements a simple Weighted Round Robin strategy between two endpoints
resource "aws_route53_traffic_policy" "example_policy" {
  name     = "example-weighted-policy"
  comment  = "Traffic policy to distribute load between primary and secondary endpoints"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    StartRule              = "weighted_rule"
    Endpoints = {
      primary_endpoint = {
        Type  = "value"
        Value = "1.2.3.4"
      }
      secondary_endpoint = {
        Type  = "value"
        Value = "5.6.7.8"
      }
    }
    Rules = {
      weighted_rule = {
        RuleType = "weighted"
        Items = [
          {
            EndpointReference = "primary_endpoint"
            Weight            = "80"
          },
          {
            EndpointReference = "secondary_endpoint"
            Weight            = "20"
          }
        ]
      }
    }
  })
}

# Create a Traffic Policy Instance to apply the policy to a specific DNS name
# Note: You must have an existing Hosted Zone (represented here by data source or ID)
resource "aws_route53_traffic_policy_instance" "example_instance" {
  name                   = "app.example.com"
  traffic_policy_id      = aws_route53_traffic_policy.example_policy.id
  traffic_policy_version = aws_route53_traffic_policy.example_policy.version
  hosted_zone_id         = "Z1234567890ABC" # Replace with your actual Hosted Zone ID
  ttl                    = 60
}

output "traffic_policy_id" {
  value = aws_route53_traffic_policy.example_policy.id
}

output "traffic_policy_instance_id" {
  value = aws_route53_traffic_policy_instance.example_instance.id
}

