# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# Data sources for current AWS identity and ECR image
data "aws_caller_identity" "current" {}

data "aws_ecr_image" "service_image" {
  repository_name = "my-app-repo"
  image_tag       = "stable"
}

# Local variables for tagging and configuration
locals {
  workspace_name = terraform.workspace
  image_tag      = data.aws_ecr_image.service_image.image_tag

  common_tags = {
    Environment = local.workspace_name
    Owner       = data.aws_caller_identity.current.arn
    ManagedBy   = "Terraform"
  }
}

# EKS Module to provision cluster and node groups
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = "${local.workspace_name}-eks-cluster"
  cluster_version = "1.27"

  vpc_id     = "vpc-12345678"
  subnet_ids = ["subnet-abc123", "subnet-def456"]

  cluster_endpoint_public_access = true

  eks_managed_node_groups = {
    default = {
      instance_types = ["t3.medium"]
      min_size     = 1
      max_size     = 3
      desired_size = 2
    }
  }

  tags = local.common_tags
}

# Kubernetes provider configuration using module outputs
provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  cluster_ca_certificate = base64decode(module.eks.cluster_certificate_authority_data)
  exec {
    api_version = "client.authentication.k8s.io/v1beta1"
    command     = "aws"
    args        = ["eks", "get-token", "--cluster-name", module.eks.cluster_name]
  }
}

# Helm provider configuration using module outputs
provider "helm" {
  kubernetes {
    host                   = module.eks.cluster_endpoint
    cluster_ca_certificate = base64decode(module.eks.cluster_certificate_authority_data)
    exec {
      api_version = "client.authentication.k8s.io/v1beta1"
      command     = "aws"
      args        = ["eks", "get-token", "--cluster-name", module.eks.cluster_name]
    }
  }
}

