provider "aws" {
  region = "us-east-1"
}

# Resource to associate an access policy with an EKS Cluster
# This defines who (principal) has what permissions (policy) and where (scope)
resource "aws_eks_access_entry" "example" {
  cluster_name      = "example-cluster"
  principal_arn     = "arn:aws:iam::123456789012:role/example-role"
  kubernetes_groups = ["example-group"]
  type              = "STANDARD"
}

resource "aws_eks_access_policy_association" "example" {
  cluster_name  = "example-cluster"
  policy_arn    = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSViewPolicy"
  principal_arn = "arn:aws:iam::123456789012:role/example-role"

  access_scope {
    type       = "namespace"
    namespaces = ["example-namespace"]
  }

  # Ensure the access entry exists before associating the policy
  depends_on = [aws_eks_access_entry.example]
}

