  cluster_name = data.aws_eks_cluster.example.name

  oidc {
    client_id                     = "your-client-id"
    identity_provider_config_name = "example-oidc-config"
    issuer_url                    = data.aws_eks_cluster.example.identity[0].oidc[0].issuer
  }
}

