extracted_code:
# Terraform configuration for an S3 bucket with security best practices
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"

  # Prevent accidental deletion through Terraform lifecycle management
  lifecycle {
    prevent_destroy = true
  }
}

# 2. Set the Bucket ACL to Private
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.test_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "test_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.example]

  bucket = aws_s3_bucket.test_bucket.id
  acl    = "private"
}

# 3. Enable Versioning (Standard practice for preventing accidental data loss)
resource "aws_s3_bucket_versioning" "test_bucket_versioning" {
  bucket = aws_s3_bucket.test_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 4. Enable AES256 Default Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "test_bucket_encryption" {
  bucket = aws_s3_bucket.test_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 5. Apply Public Access Block (Block all public access)
resource "aws_s3_bucket_public_access_block" "test_bucket_public_access" {
  bucket = aws_s3_bucket.test_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

