terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "eu-west-1" # Update to your desired region
}

resource "aws_s3_bucket" "infra_bucket" {
  bucket        = "wellcomecollection-platform-infra"
  force_destroy = false # Safeguard against accidental deletion

  lifecycle {
    prevent_destroy = true # Hard safeguard at the Terraform provider level
  }
}

resource "aws_s3_bucket_ownership_controls" "infra_bucket_ownership" {
  bucket = aws_s3_bucket.infra_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "infra_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.infra_bucket_ownership]

  bucket = aws_s3_bucket.infra_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_versioning" "infra_bucket_versioning" {
  bucket = aws_s3_bucket.infra_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "infra_bucket_lifecycle" {
  depends_on = [aws_s3_bucket_versioning.infra_bucket_versioning]
  bucket     = aws_s3_bucket.infra_bucket.id

  # Rule for tmp/ prefix
  rule {
    id     = "expire-tmp-objects"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  # Rule for versioning transitions and expirations
  rule {
    id     = "manage-versions"
    status = "Enabled"

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

resource "aws_s3_bucket_public_access_block" "infra_bucket_access" {
  bucket = aws_s3_bucket.infra_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

