variable "bucket_suffix" {
  type    = string
  default = "test"
}

# --- CloudGoat Data Bucket ---
resource "aws_s3_bucket" "cloudgoat_bucket" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_ownership" {
  bucket = aws_s3_bucket.cloudgoat_bucket.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_ownership]
  bucket     = aws_s3_bucket.cloudgoat_bucket.id
  acl        = "private"
}

# --- Website Data Bucket ---
resource "aws_s3_bucket" "web_data_bucket" {
  bucket = "website-data-${var.bucket_suffix}"
}

resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data_bucket.id
  key    = "order_data2.csv"
  source = "./order_data2.csv" # Ensure this file exists in your local directory
}

resource "aws_s3_bucket_public_access_block" "web_data_pab" {
  bucket                  = aws_s3_bucket.web_data_bucket.id
  block_public_acls       = true
  ignore_public_acls      = true
  restrict_public_buckets = true
  block_public_policy     = false # Set to false to allow the bucket policy defined below
}

resource "aws_s3_bucket_policy" "web_data_policy" {
  bucket = aws_s3_bucket.web_data_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPublicPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data_bucket.arn}/*"
      }
    ]
  })
}

