provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket        = "my-unique-bucket-name-${random_string.suffix.result}"
  force_destroy = true
}

# Helper to ensure uniqueness
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# 2. Manage Ownership Controls (Required for ACLs in many modern accounts)
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.my_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Disable Public Access Block (Required to allow public policies/ACLs)
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.my_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Apply Bucket ACL
resource "aws_s3_bucket_acl" "my_bucket_acl" {
  depends_on = [
    aws_s3_bucket_ownership_controls.example,
    aws_s3_bucket_public_access_block.example,
  ]

  bucket = aws_s3_bucket.my_bucket.id
  acl    = "private"
}

# 5. Apply Bucket Policy with Referer Condition
resource "aws_s3_bucket_policy" "allow_referer_access" {
  bucket = aws_s3_bucket.my_bucket.id
  policy = data.aws_iam_policy_document.allow_referer.json
}

data "aws_iam_policy_document" "allow_referer" {
  statement {
    sid       = "AllowGetObjectWithReferer"
    effect    = "Allow"
    principal = "*"
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.my_bucket.arn}/*"]

    condition {
      test     = "StringLike"
      variable = "aws:Referer"
      values   = ["https://www.example.com/*", "https://example.com/*"]
    }
  }
}

