# Terraform configuration for AWS S3 Buckets with Logging
# Provisions a source bucket and a target logging bucket with appropriate permissions

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Target Bucket for storing logs
resource "aws_s3_bucket" "log_bucket" {
  bucket        = "my-tf-log-destination-bucket-${random_id.suffix.hex}"
  force_destroy = true
}

# Enable ACLs for the logging bucket
resource "aws_s3_bucket_ownership_controls" "log_bucket_oc" {
  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "log_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket_oc]

  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# 2. Source Bucket that will be logged
resource "aws_s3_bucket" "source_bucket" {
  bucket        = "my-tf-source-data-bucket-${random_id.suffix.hex}"
  force_destroy = true
}

# Ensure the source bucket is private
resource "aws_s3_bucket_ownership_controls" "source_bucket_oc" {
  bucket = aws_s3_bucket.source_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "source_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.source_bucket_oc]

  bucket = aws_s3_bucket.source_bucket.id
  acl    = "private"
}

# 3. Configure Logging connection
resource "aws_s3_bucket_logging" "source_bucket_logging" {
  bucket = aws_s3_bucket.source_bucket.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "log/system-access-logs/"
}

