# Terraform configuration for a custom VPC, two subnets, and two EC2 instances with EBS volumes

provider "aws" {
  region = "us-east-1"
}

# 1. Create the bespoke VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "bespoke-vpc"
  }
}

# 2. Create an Internet Gateway for connectivity
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

# 3. Create two subnets in different AZs
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "subnet-us-east-1a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "subnet-us-east-1b"
  }
}

# 4. Fetch the most recent Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 5. Launch EC2 instance in Subnet A
resource "aws_instance" "instance_a" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_a.id

  # EBS configuration (Root volume)
  root_block_device {
    volume_size = 50
    volume_type = "gp2"
  }

  tags = {
    Name = "instance-1a"
  }
}

# 6. Launch EC2 instance in Subnet B
resource "aws_instance" "instance_b" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_b.id

  # EBS configuration (Root volume)
  root_block_device {
    volume_size = 50
    volume_type = "gp2"
  }

  tags = {
    Name = "instance-1b"
  }
}

