# Terraform configuration for VPC with public/private subnets and a Cluster Placement Group

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# 2. Subnets
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"
  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a" # Instances in a cluster placement group must be in the same AZ
  tags = {
    Name = "private-subnet"
  }
}

# 3. Networking Components
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# 4. Placement Group (Cluster Strategy)
resource "aws_placement_group" "compute_cluster" {
  name     = "compute-cluster-pg"
  strategy = "cluster"
}

# 5. Security Group
resource "aws_security_group" "ec2_sg" {
  name        = "cluster-sg"
  description = "Allow internal traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_block  = "0.0.0.0/0"
  }
}

# 6. EC2 Instances
resource "aws_instance" "cluster_nodes" {
  count         = 3
  ami           = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 AMI in us-east-1
  instance_type = "t3.medium"             # Note: Cluster placement groups usually require specific instance types

  subnet_id              = aws_subnet.private.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  placement_group        = aws_placement_group.compute_cluster.id

  tags = {
    Name = "cluster-node-${count.index + 1}"
  }
}

