# Terraform configuration to set up an AWS ElastiCache Memcached cluster

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Networking: VPC and Subnets (Assuming existing or default VPC for brevity)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Security Group to allow access to Memcached (Default port 11211)
resource "aws_security_group" "memcached_sg" {
  name        = "memcached-sg"
  description = "Allow Memcached inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 11211
    to_port     = 11211
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Subnet Group for the cluster
resource "aws_elasticache_subnet_group" "memcached_subnet_group" {
  name       = "memcached-subnet-group"
  subnet_ids = data.aws_subnets.default.ids
}

# Parameter Group for custom Memcached settings
resource "aws_elasticache_parameter_group" "memcached_params" {
  name   = "memcached-params"
  family = "memcached1.6"

  parameter {
    name  = "max_item_size"
    value = "10485760" # 10MB
  }
}

# Memcached Cluster Resource
resource "aws_elasticache_cluster" "memcached_cluster" {
  cluster_id           = "tf-memcached-cluster"
  engine               = "memcached"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 2
  parameter_group_name = aws_elasticache_parameter_group.memcached_params.name
  port                 = 11211
  subnet_group_name    = aws_elasticache_subnet_group.memcached_subnet_group.name
  security_group_ids   = [aws_security_group.memcached_sg.id]
  az_mode              = "cross-az" # Distributes nodes across availability zones

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Output the Configuration Endpoint
output "memcached_configuration_endpoint" {
  description = "The configuration endpoint to connect to the Memcached cluster"
  value       = aws_elasticache_cluster.memcached_cluster.configuration_endpoint
}

