terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable definitions for sensitive info
variable "redshift_admin_username" {
  type    = string
  default = "adminuser"
}

variable "redshift_admin_password" {
  type      = string
  sensitive = true
  default   = "Password123!" # Replace with a secure value or use an environment variable
}

# Redshift Cluster Configuration
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "terraform-redshift-cluster"
  database_name      = "dev"
  master_username    = var.redshift_admin_username
  master_password    = var.redshift_admin_password
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Automatic Snapshot Configuration
  # This sets the retention period. Snapshots are taken periodically by AWS.
  automated_snapshot_retention_period = 7

  # To enforce a specific 12-hour interval via a Snapshot Schedule
  snapshot_schedule_identifier = aws_redshift_snapshot_schedule.every_12_hours.id

  # Skip final snapshot for easy cleanup in test environments
  skip_final_snapshot = true
}

# Definition of the 12-hour snapshot schedule
resource "aws_redshift_snapshot_schedule" "every_12_hours" {
  identifier = "every-12-hours-schedule"
  definitions = [
    "rate(12 hours)"
  ]
}

# Association of the schedule to the cluster
resource "aws_redshift_snapshot_schedule_association" "example" {
  cluster_identifier = aws_redshift_cluster.example.id
  schedule_identifier = aws_redshift_snapshot_schedule.every_12_hours.id
}

