extracted_code:
# Terraform configuration for a fault-tolerant Amazon Redshift cluster
# Spanning us-east-1a and us-east-1b using a Subnet Group

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "subnet_1a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1a"
  }
}

resource "aws_subnet" "subnet_1b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-1b"
  }
}

# Redshift Subnet Group defines the AZs the cluster can utilize
resource "aws_redshift_subnet_group" "redshift_sg" {
  name       = "redshift-multi-az-subnet-group"
  subnet_ids = [aws_subnet.subnet_1a.id, aws_subnet.subnet_1b.id]

  tags = {
    Environment = "Production"
  }
}

# --- Security ---

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Redshift Cluster ---

resource "aws_redshift_cluster" "fault_tolerant_cluster" {
  cluster_identifier = "fault-tolerant-redshift-cluster"
  database_name      = "dev"
  master_username    = "adminuser"
  master_password    = "MustBeComplex123!" # Ideally sourced from Secret Manager
  node_type          = "ra3.4xlarge"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Networking & Availability
  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_sg.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]

  # Enabling Multi-AZ deployment for high availability (RA3 nodes support this)
  multi_az = true

  # Reliability Settings
  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sat:05:00-sat:09:00"
  publicly_accessible                = false
  encrypted                          = true

  tags = {
    Name = "Redshift-MultiAZ"
  }
}

