  master_password    = "MustBe8Characters1!" # Use a secrets manager in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Attach the IAM Role created above
  iam_roles = [aws_iam_role.redshift_role.arn]

  # Skip final snapshot for easy cleanup (not recommended for production)
