# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and Networking for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound access to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier  = "tf-redshift-cluster"
  database_name       = "mydb"
  master_username     = "adminuser"
  master_password     = "MustBe8Characters1!" # Use secrets management in production
  node_type           = "dc2.large"
  cluster_type        = "multi-node"
  number_of_nodes     = 2
  skip_final_snapshot = true

  cluster_subnet_group_name    = aws_redshift_subnet_group.main.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  publicly_accessible          = true
}

# Redshift Endpoint Access (Interface VPC Endpoint)
resource "aws_vpc_endpoint" "redshift" {
  vpc_id            = aws_vpc.redshift_vpc.id
  service_name      = "com.amazonaws.us-east-1.redshift"
  vpc_endpoint_type = "Interface"

  security_group_ids = [aws_security_group.redshift_sg.id]
  subnet_ids         = [aws_subnet.redshift_subnet_1.id]

  private_dns_enabled = true
}

# Redshift Managed VPC Endpoint (Redshift-specific endpoint access)
resource "aws_redshift_endpoint_access" "example" {
  endpoint_name      = "redshift-endpoint"
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
  resource_owner     = aws_redshift_cluster.example.cluster_account_id
  subnet_group_name  = aws_redshift_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "managed_vpc_endpoint" {
  value = aws_redshift_endpoint_access.example.address
}

