# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a DynamoDB table with Streams enabled
resource "aws_dynamodb_table" "example" {
  name             = "example-stream-table"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "UserId"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "UserId"
    type = "S"
  }
}

# 2. Create an IAM Role for the Lambda function
resource "aws_iam_role" "iam_for_lambda" {
  name = "lambda_dynamodb_stream_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 3. Attach basic execution and DynamoDB stream permissions to the role
resource "aws_iam_role_policy_attachment" "lambda_policy" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaDynamoDBExecutionRole"
}

# 4. Create the Lambda function
resource "aws_lambda_function" "example" {
  filename      = "lambda_function_payload.zip" # Ensure this file exists locally
  function_name = "example_dynamodb_stream_handler"
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      TABLE_NAME = aws_dynamodb_table.example.name
    }
  }
}

# 5. Create the Event Source Mapping
resource "aws_lambda_event_source_mapping" "example" {
  event_source_arn  = aws_dynamodb_table.example.stream_arn
  function_name     = aws_lambda_function.example.arn
  starting_position = "LATEST"
  batch_size        = 100

  # Optional: Filtering criteria to only process specific events
  filter_criteria {
    filter {
      pattern = jsonencode({
        eventName = ["INSERT", "MODIFY"]
      })
    }
  }
}

