# Terraform configuration to enable DynamoDB Contributor Insights for a table

provider "aws" {
  region = "us-east-1"
}

# 1. Define the DynamoDB Table
resource "aws_dynamodb_table" "main_table" {
  name           = "UserMetricsTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"
  range_key      = "Timestamp"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  attribute {
    name = "Category"
    type = "S"
  }

  # Define a Global Secondary Index (GSI)
  global_secondary_index {
    name               = "CategoryIndex"
    hash_key           = "Category"
    range_key          = "Timestamp"
    projection_type    = "ALL"
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# 2. Enable Contributor Insights for the base table
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.main_table.name
}

# 3. Enable Contributor Insights for the Global Secondary Index (GSI)
resource "aws_dynamodb_contributor_insights" "gsi_insights" {
  table_name = aws_dynamodb_table.main_table.name
  index_name = "CategoryIndex"

  # Ensure the table insights are created or handled in parallel
  depends_on = [aws_dynamodb_table.main_table]
}

