# Terraform configuration to set up a Kinesis Data Stream as a destination for a DynamoDB Table

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the DynamoDB Table
resource "aws_dynamodb_table" "example" {
  name             = "example-table"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "UserId"

  attribute {
    name = "UserId"
    type = "S"
  }

  tags = {
    Environment = "production"
  }
}

# 2. Create the Kinesis Data Stream
resource "aws_kinesis_stream" "example" {
  name             = "dynamodb-stream-destination"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes",
  ]

  tags = {
    Environment = "production"
  }
}

# 3. Enable Kinesis Streaming Destination for the DynamoDB Table
resource "aws_dynamodb_kinesis_streaming_destination" "example" {
  stream_arn = aws_kinesis_stream.example.arn
  table_name = aws_dynamodb_table.example.name
}

