# This configuration creates a DynamoDB Global Table (Version 2019.11.21)
# Global tables use multi-region replication. Each replica must be defined within the resource.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# The main provider for the primary region
provider "aws" {
  region = "us-east-1"
}

# The alias provider for the replica region
provider "aws" {
  alias  = "replica"
  region = "us-west-2"
}

resource "aws_dynamodb_table" "global_table" {
  name             = "MyGlobalTable"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "UserId"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "UserId"
    type = "S"
  }

  # Primary replica (us-east-1)
  replica {
    region_name = "us-east-1"
  }

  # Additional replica (us-west-2)
  # Note: The provider listed in the replica block is used for managing the replica's KMS keys or tags if specified.
  replica {
    region_name = "us-west-2"
  }

  tags = {
    Environment = "Production"
    Terraform   = "true"
  }
}

