# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for DAX
resource "aws_iam_role" "dax_role" {
  name = "DAXServiceRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# Attach policy to allow DAX to access DynamoDB
resource "aws_iam_role_policy_attachment" "dax_dynamodb_access" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Subnet Group for DAX (Requires existing VPC subnets)
resource "aws_dax_subnet_group" "example" {
  name       = "my-dax-subnet-group"
  subnet_ids = ["subnet-0123456789abcdef0", "subnet-0123456789abcdef1"] # Replace with valid Subnet IDs
}

# DAX Cluster Configuration
resource "aws_dax_cluster" "example" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
  replication_factor = 1

  subnet_group_name  = aws_dax_subnet_group.example.name

  description        = "DAX cluster with r4.large nodes"

  # Default maintenance window and notification settings
  maintenance_window = "sun:05:00-sun:09:00"

  server_side_encryption {
    enabled = true
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

