# Terraform configuration to create a custom Amazon DAX (DynamoDB Accelerator) Parameter Group

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_dax_parameter_group" "personalized_dax_params" {
  name         = "personalized-dax-parameter-group"
  description = "A custom parameter group for DAX to optimize TTL and query cache settings"

  # Example parameters to personalize the DAX behavior:
  # query-ttl-millis: How long query results remain in the cache (e.g., 5 minutes)
  parameters {
    name  = "query-ttl-millis"
    value = "300000"
  }

  # record-ttl-millis: How long individual items remain in the cache (e.g., 10 minutes)
  parameters {
    name  = "record-ttl-millis"
    value = "600000"
  }
}

output "parameter_group_id" {
  value       = aws_dax_parameter_group.personalized_dax_params.id
  description = "The name of the DAX parameter group"
}

