# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the SageMaker Domain
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "sagemaker-vpc"
  }
}

# 2. Create a Subnet
resource "aws_subnet" "sagemaker_subnet" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "sagemaker-subnet"
  }
}

# 3. Create an IAM Execution Role for the Domain
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-domain-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach AmazonSageMakerFullAccess policy to the role
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 4. Create the SageMaker Domain
resource "aws_sagemaker_domain" "example" {
  domain_name             = "my-sagemaker-domain"
  auth_mode               = "IAM"
  vpc_id                  = aws_vpc.sagemaker_vpc.id
  subnet_ids              = [aws_subnet.sagemaker_subnet.id]
  app_network_access_type = "VpcOnly"

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "system"
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  retention_policy {
    home_efs_file_system = "Retain"
  }

  tags = {
    Environment = "Development"
  }
}

# 5. Optional: Create a User Profile within the Domain
resource "aws_sagemaker_user_profile" "example_user" {
  domain_id         = aws_sagemaker_domain.example.id
  user_profile_name = "data-scientist-1"

  user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn
  }
}

