# Terraform configuration to provision an AWS SageMaker Space
# This requires an existing SageMaker Domain ID.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable for the SageMaker Domain ID (required for a Space)
variable "sagemaker_domain_id" {
  type        = string
  description = "The ID of the existing SageMaker Domain"
}

# SageMaker Space Resource
resource "aws_sagemaker_space" "example" {
  domain_id  = var.sagemaker_domain_id
  space_name = "example-collaborative-space"

  space_settings {
    app_type = "JupyterServer"

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type       = "system" # Default for JupyterServer
        sage_maker_image_arn = "arn:aws:sagemaker:us-east-1:081325390128:image/jupyter-server-3"
      }
    }
  }

  space_sharing_settings {
    sharing_type = "Private"
  }

  tags = {
    Environment = "Dev"
    Project     = "SageMaker-Collaboration"
  }
}

output "sagemaker_space_arn" {
  value       = aws_sagemaker_space.example.arn
  description = "The ARN of the SageMaker Space"
}

