```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a SageMaker Code Repository pointing to the specified Git repository
resource "aws_sagemaker_code_repository" "example" {
  code_repository_name = "example-repo"

  git_config {
    repository_url = "https://github.com/hashicorp/terraform-provider-aws.git"

    # Optional: Branch can be specified if needed
    # branch = "main"

    # Note: If this were a private repository, you would provide a 'secret_arn' 
    # referencing an AWS Secrets Manager secret containing credentials.
  }
}
```

