# Terraform configuration to create an AWS SageMaker Image and Image Version

resource "aws_iam_role" "sagemaker_image_role" {
  name = "sagemaker-image-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_image_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

resource "aws_sagemaker_image" "custom_image" {
  image_name   = "custom-ml-runtime-image"
  role_arn     = aws_iam_role.sagemaker_image_role.arn
  display_name = "Custom ML Runtime"
  description  = "A custom SageMaker image for specialized ML workloads"

  tags = {
    Environment = "Development"
    Framework   = "PyTorch"
  }
}

resource "aws_sagemaker_image_version" "v1" {
  image_name = aws_sagemaker_image.custom_image.id
  # Base image URI (e.g., from ECR)
  base_image = "123456789012.dkr.ecr.us-east-1.amazonaws.com/my-custom-repo:latest"
}

# Documentation on requirements:
# 1. The 'base_image' must be a valid Docker image stored in ECR.
# 2. The IAM role must have permissions to pull from the specified ECR repository.

