extracted_code:
# Terraform configuration to provision an AWS SageMaker Model using the KMeans built-in algorithm container

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Fetch the current region and account ID to construct the ECR URI
data "aws_region" "current" {}

# IAM Role for SageMaker to access resources (S3, CloudWatch, etc.)
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker_kmeans_model_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Model using the KMeans container image
# The image URI follows the pattern: <account-id>.dkr.ecr.<region>.amazonaws.com/kmeans:1
# Note: AWS account IDs for built-in algorithms vary by region. 
# For us-east-1, the KMeans registry account is 382416733822.
resource "aws_sagemaker_model" "kmeans_model" {
  name               = "sagemaker-kmeans-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    # This URI is specific to the KMeans algorithm in us-east-1.
    # Replace '382416733822' with the correct ID for your region if not using us-east-1.
    image          = "382416733822.dkr.ecr.${data.aws_region.current.name}.amazonaws.com/kmeans:1"
    model_data_url = "s3://my-sagemaker-bucket/kmeans-artifacts/model.tar.gz"
  }

  tags = {
    Name        = "SageMakerKMeansModel"
    Environment = "Production"
  }
}

