  name = "sagemaker-pipeline-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Basic policy attachment for SageMaker access
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_pipeline_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Pipeline Resource
resource "aws_sagemaker_pipeline" "example_pipeline" {
  pipeline_name         = "example-ml-pipeline"
  pipeline_display_name = "Example-ML-Pipeline"
  role_arn             = aws_iam_role.sagemaker_pipeline_role.arn

  # The pipeline definition is a JSON string following the SageMaker Pipeline Definition DAG schema.
  # This example shows a minimal skeleton definition.
  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Parameters = [
      {
        Name = "ProcessingInstanceCount"
        Type = "Integer"
        DefaultValue = 1
      }
    ]
    Steps = [
      {
        Name = "ExamplePlaceholderStep"
        Type = "Training" # Example step type; requires complete configuration in a real scenario
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = "683313684715.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
            TrainingInputMode = "File"
          }
          # In a real scenario, you would define InputDataConfig, OutputDataConfig, and ResourceConfig here
        }
      }
    ]
  })

  tags = {
    Environment = "Development"
    Project     = "Terraform-SageMaker"
  }
}

output "pipeline_arn" {
  value       = aws_sagemaker_pipeline.example_pipeline.arn
  description = "The Amazon Resource Name of the created SageMaker Pipeline."
}
```

