# Terraform configuration to create a SageMaker Endpoint Configuration and Endpoint 
# for an existing SageMaker model.

provider "aws" {
  region = "us-east-1"
}

# 1. Define the SageMaker Endpoint Configuration
# This references the existing model name and defines resources
resource "aws_sagemaker_endpoint_configuration" "this" {
  name = "my-sagemaker-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = "existing-sagemaker-model-name" # Replace with your actual model name
    initial_instance_count = 1
    instance_type          = "ml.m5.xlarge"
    initial_variant_weight = 1.0
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# 2. Deploy the SageMaker Endpoint
# This creates the actual HTTP(S) interface to perform real-time inferences
resource "aws_sagemaker_endpoint" "this" {
  name                 = "my-sagemaker-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.this.name

  tags = {
    Name = "my-sagemaker-endpoint"
  }
}

# Output the endpoint ARN for reference
output "sagemaker_endpoint_arn" {
  value = aws_sagemaker_endpoint.this.arn
}

