    initial_variant_weight = 1.0
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# 2. Deploy the SageMaker Endpoint
# This creates the actual HTTP(S) interface to perform real-time inferences
resource "aws_sagemaker_endpoint" "this" {
  name                 = "my-sagemaker-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.this.name

  tags = {
    Name = "my-sagemaker-endpoint"
  }
}

# Output the endpoint ARN for reference
output "sagemaker_endpoint_arn" {
  value = aws_sagemaker_endpoint.this.arn
}
```

