# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Data source to fetch the most recent Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Provision the EC2 instance
# c5.large is used here as it provides 2 vCPUs and supports CPU options configuration
resource "aws_instance" "app_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "c5.large"

  # Optimize CPU options: 1 core with 2 threads per core = 2 vCPUs
  cpu_options {
    core_count       = 1
    threads_per_core = 2
  }

  tags = {
    Name = "AmazonLinux2-CustomCPU"
  }
}

