extracted_code:
# Terraform configuration to launch two EC2 instances in private subnets 
# sharing a single Amazon EFS file system.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# --- Security Groups ---

resource "aws_security_group" "ec2_sg" {
  name        = "ec2-efs-sg"
  description = "Allow SSH and EFS traffic"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "efs_sg" {
  name        = "efs-mount-sg"
  description = "Allow NFS traffic from EC2 instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    security_groups = [aws_security_group.ec2_sg.id]
  }
}

# --- EFS File System ---

resource "aws_efs_file_system" "shared_storage" {
  creation_token = "shared-ec2-storage"
  encrypted      = true

  tags = {
    Name = "SharedStorage"
  }
}

resource "aws_efs_mount_target" "mount_a" {
  file_system_id  = aws_efs_file_system.shared_storage.id
  subnet_id       = aws_subnet.private_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_efs_mount_target" "mount_b" {
  file_system_id  = aws_efs_file_system.shared_storage.id
  subnet_id       = aws_subnet.private_b.id
  security_groups = [aws_security_group.efs_sg.id]
}

# --- EC2 Instances ---

data "aws_ami" "amazon_linux_2023" {
  most_recent = true
  owners      = ["amazon"]
  filter {
    name   = "name"
    values = ["al2023-ami-kernel-*-x86_64"]
  }
}

# User data script to mount the EFS at boot
locals {
  user_data = <<-EOT
    #!/bin/bash
    dnf install -y amazon-efs-utils
    mkdir -p /mnt/efs
    mount -t efs -o tls ${aws_efs_file_system.shared_storage.id}:/ /mnt/efs
    echo "${aws_efs_file_system.shared_storage.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
  EOT
}

resource "aws_instance" "app_server_1" {
  ami                    = data.aws_ami.amazon_linux_2023.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_a.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  user_data              = local.user_data

  tags = {
    Name = "EFS-Client-1"
  }

  depends_on = [aws_efs_mount_target.mount_a]
}

resource "aws_instance" "app_server_2" {
  ami                    = data.aws_ami.amazon_linux_2023.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_b.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  user_data              = local.user_data

  tags = {
    Name = "EFS-Client-2"
  }

  depends_on = [aws_efs_mount_target.mount_b]
}

