# Terraform configuration for an AWS Elasticache Redis Cluster to minimize database queries
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Security Group for the Cache
resource "aws_security_group" "redis_sg" {
  name        = "redis-cache-sg"
  description = "Allow application traffic to Redis"

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Should be restricted to your App VPC CIDR
  }
}

# 2. Redis Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = "cache-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with actual Subnet IDs
}

# 3. Redis Replication Group (Cluster Mode Disabled for standard caching)
resource "aws_elasticache_replication_group" "primary_cache" {
  replication_group_id          = "db-query-cache"
  replication_group_description = "Redis cluster to cache frequent DB queries"
  node_type                     = "cache.t3.medium"
  port                          = 6379
  parameter_group_name          = "default.redis7"
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.redis_sg.id]

  # High Availability Settings
  automatic_failover_enabled = true
  multi_az_enabled          = true
  num_cache_clusters         = 2 # One primary, one replica

  # Maintenance & Backup
  maintenance_window      = "sun:05:00-sun:06:00"
  snapshot_retention_limit = 5
  snapshot_window          = "00:00-01:00"

  tags = {
    Environment = "Production"
    Purpose     = "Query-Latency-Reduction"
  }
}

# Outputs to provide to the Application
output "redis_endpoint" {
  value       = aws_elasticache_replication_group.primary_cache.primary_endpoint_address
  description = "The endpoint to connect the application to for caching"
}

response:
To minimize the frequency of database queries, the most effective strategy is to implement an **Elasticache (Redis) Cluster** as a caching layer. This "Cache-Aside" pattern allows the application to store the results of expensive queries in memory, significantly reducing the load on the backend database.

```hcl
# Terraform configuration for an AWS Elasticache Redis Cluster to minimize database queries
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Security Group for the Cache
resource "aws_security_group" "redis_sg" {
  name        = "redis-cache-sg"
  description = "Allow application traffic to Redis"

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Should be restricted to your App VPC CIDR
  }
}

# 2. Redis Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = "cache-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with actual Subnet IDs
}

# 3. Redis Replication Group (Cluster Mode Disabled for standard caching)
resource "aws_elasticache_replication_group" "primary_cache" {
  replication_group_id          = "db-query-cache"
  replication_group_description = "Redis cluster to cache frequent DB queries"
  node_type                     = "cache.t3.medium"
  port                          = 6379
  parameter_group_name          = "default.redis7"
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.redis_sg.id]

  # High Availability Settings
  automatic_failover_enabled = true
  multi_az_enabled          = true
  num_cache_clusters         = 2 # One primary, one replica

  # Maintenance & Backup
  maintenance_window      = "sun:05:00-sun:06:00"
  snapshot_retention_limit = 5
  snapshot_window          = "00:00-01:00"

  tags = {
    Environment = "Production"
    Purpose     = "Query-Latency-Reduction"
  }
}

# Outputs to provide to the Application
output "redis_endpoint" {
  value       = aws_elasticache_replication_group.primary_cache.primary_endpoint_address
  description = "The endpoint to connect the application to for caching"
}
```

