# 1. Define the IAM Authenticated User
# Note: The user_id and user_name must be identical for IAM authentication
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-user-01"
  user_name     = "iam-user-01"
  engine        = "REDIS"
  access_string = "on ~* +@all" # Full access to all keys and commands; restrict as needed

  authentication_mode {
    type = "iam"
  }
}

# 2. Add the user to a User Group
resource "aws_elasticache_user_group" "example" {
  engine        = "REDIS"
  user_group_id = "iam-authenticated-group"
  user_ids      = ["default", aws_elasticache_user.iam_user.user_id]
}

# 3. Create the Replication Group with IAM Auth enabled
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "iam-redis-cluster"
  description                = "Redis cluster with IAM authentication"
  node_type                  = "cache.t3.micro"
  port                       = 6379
  parameter_group_name       = "default.redis7" # IAM auth requires Redis 7.0 or later
  engine_version             = "7.0"

  # Transit encryption is REQUIRED for IAM authentication
  transit_encryption_enabled = true

  # Associate the User Group
  user_group_ids             = [aws_elasticache_user_group.example.user_group_id]
}

# 4. IAM Policy for the Client (EC2/Lambda/etc) to authenticate
resource "aws_iam_policy" "elasticache_iam_auth" {
  name        = "ElastiCacheIAMAuthPolicy"
  description = "Allows client to connect to ElastiCache using IAM"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "elasticache:Connect"
        Effect   = "Allow"
        Resource = [
          "arn:aws:elasticache:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:user:${aws_elasticache_user.iam_user.user_id}"
        ]
      }
    ]
  })
}

