# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for DAX Cluster
resource "aws_iam_role" "dax_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy Attachment for DAX to access DynamoDB
resource "aws_iam_role_policy_attachment" "dax_dynamo_access" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "example" {
  name       = "example-dax-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with valid subnet IDs
}

# DAX Security Group
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Security group for DAX cluster"

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Adjust based on your VPC CIDR
  }
}

# DAX Cluster Provisioning
resource "aws_dax_cluster" "example" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
  replication_factor = 1

  subnet_group_name  = aws_dax_subnet_group.example.name
  security_group_ids = [aws_security_group.dax_sg.id]

  server_side_encryption {
    enabled = true
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

