```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Variable definitions
variable "vpc_id" {
  type    = string
  default = "vpc-xxxxxxxxxxxxxxxxx"
}

variable "subnet_ids" {
  type    = list(string)
  default = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy", "subnet-zzzzzzzzzzzzzzzzz"]
}

# KMS Key for Encryption at Rest
resource "aws_kms_key" "msk_key" {
  description             = "KMS key for Amazon MSK encryption at rest"
  deletion_window_in_days = 7
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Recommendation: Restrict to your VPC CIDR
  }
}

# Amazon MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = var.subnet_ids
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    # Encryption at rest using the KMS key created above
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn

    # Encryption in transit
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# CloudWatch Log Group for MSK
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/example-cluster"
  retention_in_days = 7
}

output "zookeeper_connect_string" {
  value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}
```

