# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Data source to get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Subnets in three different AZs as required for MSK Serverless
resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow traffic to MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# MSK Serverless Cluster
# Note: MSK Serverless automatically manages scaling; "broker instances" count 
# is handled by AWS based on throughput, but it requires subnets in multiple AZs for HA.
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = aws_subnet.msk_subnets[*].id
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# IAM Policy to allow connecting to MSK
resource "aws_iam_policy" "msk_client_policy" {
  name        = "msk-serverless-client-policy"
  description = "Policy for MSK Serverless client access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster"
        ]
        Resource = aws_msk_serverless_cluster.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:ReadData",
          "kafka-cluster:WriteData",
          "kafka-cluster:DescribeTopic"
        ]
        Resource = "arn:aws:kafka:us-east-1:${data.aws_caller_identity.current.account_id}:topic/${aws_msk_serverless_cluster.example.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:AlterGroup",
          "kafka-cluster:DescribeGroup"
        ]
        Resource = "arn:aws:kafka:us-east-1:${data.aws_caller_identity.current.account_id}:group/${aws_msk_serverless_cluster.example.cluster_name}/*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

output "msk_cluster_arn" {
  value = aws_msk_serverless_cluster.example.arn
}

