  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-security-group"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }
}

# Logging Destinations
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "/aws/msk/my-cluster"
}

resource "aws_s3_bucket" "msk_log_bucket" {
  bucket = "msk-broker-logs-bucket-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "terraform-msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_log_bucket.arn
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_msk_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{ Action = "sts:AssumeRole", Effect = "Allow", Principal = { Service = "firehose.amazonaws.com" } }]
  })
}

# KMS Key for Encryption at Rest
resource "aws_kms_key" "msk_key" {
  description = "MSK encryption key"
}

# MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "3.2.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_log_bucket.id
        prefix  = "logs/msk"
      }
    }
  }
}

# MSK Connect Custom Plugin
resource "aws_s3_object" "plugin_zip" {
  bucket = aws_s3_bucket.msk_log_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip" # Local file path
}

resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_log_bucket.arn
      file_key   = aws_s3_object.plugin_zip.key
    }
  }
}

# MSK Connect Connector
resource "aws_iam_role" "connector_role" {
  name = "msk-connector-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{ Action = "sts:AssumeRole", Effect = "Allow", Principal = { Service = "kafkaconnect.amazonaws.com" } }]
  })
}

resource "aws_mskconnect_connector" "example_connector" {
  name = "debezium-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.postgresql.PostgresConnector"
    "tasks.max"                      = "1"
    "kafka.topic.prefix"             = "dbserver1"
    "database.hostname"              = "change-me"
    "database.port"                  = "5432"
    "database.user"                  = "postgres"
    "database.password"              = "password"
    "database.dbname"                = "postgres"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.connector_role.arn
}
```

