# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Data source for available AZs
data "aws_availability_zones" "available" {}

# Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "aurora-vpc"
  }
}

# Create subnets in different AZs (Aurora requires at least 2)
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]
}

# DB Subnet Group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-postgresql-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Aurora PostgreSQL Subnet Group"
  }
}

# Security Group to allow PostgreSQL traffic
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-postgresql-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Aurora PostgreSQL Cluster
resource "aws_rds_cluster" "postgresql" {
  cluster_identifier      = "aurora-postgresql-cluster"
  engine                  = "aurora-postgresql"
  engine_version          = "15.4"
  database_name           = "mydb"
  master_username         = "adminuser"
  master_password         = "ChangeMe123!" # In production, use secrets manager or variables
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  db_subnet_group_name    = aws_db_subnet_group.aurora.name
  vpc_security_group_ids  = [aws_security_group.aurora_sg.id]
  skip_final_snapshot     = true
}

# Aurora Cluster Instances (Primary and Replica)
resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "aurora-postgresql-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.postgresql.id
  instance_class     = "db.t3.medium"
  engine             = aws_rds_cluster.postgresql.engine
  engine_version     = aws_rds_cluster.postgresql.engine_version
  db_subnet_group_name = aws_db_subnet_group.aurora.name
}

# Output the cluster endpoint
output "cluster_endpoint" {
  value = aws_rds_cluster.postgresql.endpoint
}

