# or specific IOPS/Storage throughput can be defined for Provisioned clusters.
resource "aws_rds_cluster" "mysql" {
  cluster_identifier      = "mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.04.0"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "Password123!" # In production, use Sensitive variables or Secrets Manager
  db_subnet_group_name    = aws_db_subnet_group.main.name
  skip_final_snapshot     = true

  # For specific storage provisioning/io-optimized modes:
  storage_type            = "io1"
  iops                    = 3000 # Example provisioned IOPS
  allocated_storage       = 100  # 100 GB initial storage requirement
}

# Provision an instance in every available zone to ensure 100GB presence/availability
resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = length(data.aws_availability_zones.available.names)
  identifier         = "mysql-cluster-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.mysql.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.mysql.engine
  engine_version     = aws_rds_cluster.mysql.engine_version
  availability_zone  = data.aws_availability_zones.available.names[count.index]
  db_subnet_group_name = aws_db_subnet_group.main.name
}
