  subnet_ids = [
    aws_subnet.az_a.id,
    aws_subnet.az_b.id,
    aws_subnet.az_c.id
  ]

  tags = {
    Name = "MySQL Cluster Subnet Group"
  }
}

# Aurora MySQL Cluster
# Note: Aurora scales storage automatically, but for standard RDS Multi-AZ 
# we define the allocated_storage. This example uses Aurora for HA clustering.
resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier      = "mysql-cluster-aurora"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.04.0"
  availability_zones      = ["us-east-1a", "us-east-1b", "us-east-1c"]
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "password123" # Recommended to use Secrets Manager in production
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  db_subnet_group_name    = aws_db_subnet_group.mysql_cluster_subnet_group.name
  skip_final_snapshot     = true

  # Storage for Aurora is auto-scaling, but we can manage storage types for RDS 
  # For standard RDS instances, you would use 'allocated_storage = 100'
}

