# Terraform configuration for an AWS RDS MySQL Instance

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the database
resource "aws_vpc" "mysql_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "mysql-vpc"
  }
}

# Create a Subnet Group (RDS requires at least two subnets in different AZs)
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-main-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "MySQL DB Subnet Group"
  }
}

# Security Group to allow MySQL traffic
resource "aws_security_group" "mysql_sg" {
  name        = "allow_mysql"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.mysql_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Open to internet for demo purposes. Restrict this in production.
  }
}

# RDS MySQL Instance
resource "aws_db_instance" "mysql_db" {
  allocated_storage      = 20
  db_name                = "application_db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  username               = "admin"
  password               = "ChangeMe123!" # Ideally use a secret manager or variable
  parameter_group_name   = "default.mysql8.0"
  db_subnet_group_name   = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids = [aws_security_group.mysql_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Name = "MySQLInstance"
  }
}

output "db_endpoint" {
  value = aws_db_instance.mysql_db.endpoint
}

