# Terraform configuration for a DynamoDB Global Table (V2)
# Replicating between us-east-2 and us-west-2

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Primary provider for us-east-2
provider "aws" {
  region = "us-east-2"
}

# Secondary provider for us-west-2 replica
provider "aws" {
  alias  = "us_west_2"
  region = "us-west-2"
}

resource "aws_dynamodb_table" "global_table" {
  name             = "GlobalUserTable"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "UserId"
  range_key        = "Timestamp"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  # Replica in us-east-2 (implicit via primary provider)
  # replica {
  #   region_name = "us-east-2"
  # }

  # Replica in us-west-2
  replica {
    region_name = "us-west-2"
    point_in_time_recovery = true
    propagate_tags          = true
  }

  tags = {
    Environment = "Production"
    Global      = "true"
  }

  # Point-in-time recovery is required for many global configurations
  point_in_time_recovery {
    enabled = true
  }
}

