# Terraform configuration for an Amazon DAX (DynamoDB Accelerator) Cluster

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "dax_subnets" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
}

data "aws_availability_zones" "available" {
  state = "available"
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "main" {
  name       = "dax-subnet-group"
  subnet_ids = aws_subnet.dax_subnets[*].id
}

# IAM Role for DAX
resource "aws_iam_role" "dax_role" {
  name = "DaxServiceRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy for DAX to access DynamoDB
resource "aws_iam_role_policy" "dax_policy" {
  name = "DaxAccessPolicy"
  role = aws_iam_role.dax_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "dynamodb:*"
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

# Security Group for DAX (Port 8111 is default)
resource "aws_security_group" "dax_sg" {
  name   = "dax-security-group"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# DAX Cluster
resource "aws_dax_cluster" "main" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.t3.medium"
  replication_factor = 3
  subnet_group_name  = aws_dax_subnet_group.main.name
  security_group_ids = [aws_security_group.dax_sg.id]

  server_side_encryption {
    enabled = true
  }

  maintenance_window = "sun:05:00-sun:09:00"
}

