# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC with IPv6 support enabled (required for Egress-Only IGW)
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "main-vpc"
  }
}

# Create an Egress-Only Internet Gateway
# This allows outbound-only communication for IPv6 traffic from instances in the VPC
resource "aws_egress_only_internet_gateway" "eoigw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-egress-only-igw"
  }
}

# Example: Route table to direct IPv6 traffic to the Egress-Only Internet Gateway
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.eoigw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

