# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "main-igw"
  }
}

# 3. Create a Custom Route Table
resource "aws_route_table" "custom_rt" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "custom-route-table"
  }
}

# 4. Create a Route for the Internet Gateway
# This sends traffic for the designated CIDR (0.0.0.0/0 for internet) through the IGW
resource "aws_route" "internet_access_route" {
  route_table_id         = aws_route_table.custom_rt.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.igw.id
}

# Example Subnet to associate with the Route Table
resource "aws_subnet" "public_subnet" {
  vpc_id     = aws_vpc.main_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "public-subnet"
  }
}

# 5. Associate the Subnet with the Route Table
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.custom_rt.id
}

