# Terraform configuration for an Amazon Neptune Cluster with a custom parameter group

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Custom Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "example" {
  family      = "neptune1.2"
  name        = "example-neptune-cluster-params"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enforce_ssl"
    value = "1"
  }
}

# 2. Custom Neptune Instance Parameter Group
resource "aws_neptune_parameter_group" "example" {
  family      = "neptune1.2"
  name        = "example-neptune-instance-params"
  description = "Custom parameter group for Neptune instances"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 3. Neptune Cluster
resource "aws_neptune_cluster" "example" {
  cluster_identifier                  = "example-neptune-cluster"
  engine                              = "neptune"
  backup_retention_period             = 5
  preferred_backup_window             = "07:00-09:00"
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = true
  apply_immediately                   = true

  # Reference the custom cluster parameter group
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.example.name

  # Networking (Assumes default VPC/Subnets; replace with specific IDs if needed)
  # vpc_security_group_ids = ["sg-xxxxxxxx"]
}

# 4. Neptune Cluster Instance(s)
resource "aws_neptune_cluster_instance" "example" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.example.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  apply_immediately  = true

  # Reference the custom instance parameter group
  neptune_parameter_group_name = aws_neptune_parameter_group.example.name
}

output "neptune_endpoint" {
  value       = aws_neptune_cluster.example.endpoint
  description = "The DNS address of the Neptune instance"
}

