# Terraform configuration for an AWS Neptune Cluster with custom parameter groups 
# and network restrictions to two specific subnets.

provider "aws" {
  region = "us-east-1"
}

# 1. Define the VPC and Subnets (Placeholders for the two sample subnets)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. DB Subnet Group to restrict Neptune to the two subnets
resource "aws_neptune_subnet_group" "default" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# 3. Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom" {
  family      = "neptune1.2"
  name        = "custom-neptune-params"
  description = "Custom parameter group for neptune cluster"

  parameter {
    name  = "neptune_enforce_ssl"
    value = "1"
  }
}

# 4. Custom Instance Parameter Group
resource "aws_neptune_parameter_group" "custom_inst" {
  family      = "neptune1.2"
  name        = "custom-neptune-instance-params"
  description = "Custom parameter group for neptune instances"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 5. Security Group for Access Control
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-access-control"
  description = "Restrict access to Neptune"
  vpc_id      = aws_vpc.main.id

  # Ingress restricted to the CIDRs of the two subnets
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_a.cidr_block, aws_subnet.subnet_b.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 6. Neptune Cluster
resource "aws_neptune_cluster" "default" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  backup_retention_period             = 5
  preferred_backup_window             = "07:00-09:00"
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = false
  apply_immediately                   = true

  neptune_subnet_group_name           = aws_neptune_subnet_group.default.name
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom.name
  vpc_security_group_ids              = [aws_security_group.neptune_sg.id]
}

# 7. Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "example" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.default.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  apply_immediately  = true
  neptune_parameter_group_name = aws_neptune_parameter_group.custom_inst.name
}

output "neptune_endpoint" {
  value = aws_neptune_cluster.default.endpoint
}

