# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic for Voice Connector notifications
resource "aws_sns_topic" "chime_notifications" {
  name = "chime-voice-connector-notifications"
}

# 2. Provision the AWS Chime Voice Connector
# Note: Encryption is enabled by default for Chime Voice Connectors (TLS/SRTP)
resource "aws_chime_voice_connector" "encrypted_vc" {
  name               = "encrypted-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# 3. Configure Streaming settings
# - Data retention is set to 5 hours
# - Streaming to Kinesis is disabled (disabled = true)
# - Notifications are sent to the SNS topic
resource "aws_chime_voice_connector_streaming" "vc_streaming" {
  voice_connector_id = aws_chime_voice_connector.encrypted_vc.id
  data_retention     = 5
  disabled           = true

  streaming_notification_targets {
    notification_target = "SNS"
  }
}

# 4. Create the Logging configuration (Optional but recommended for monitoring)
resource "aws_chime_voice_connector_logging" "vc_logging" {
  voice_connector_id = aws_chime_voice_connector.encrypted_vc.id
  enable_sip_logs    = true
  enable_media_metric_logs = true
}

