```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1" # Chime Voice Connector resources are primarily managed in us-east-1 or us-west-2
}

# 1. Create the Amazon Chime Voice Connector
resource "aws_chime_voice_connector" "main" {
  name               = "my-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# 2. Create a Kinesis Video Stream to receive the media
resource "aws_kinesis_video_stream" "media_stream" {
  name                    = "chime-media-stream"
  data_retention_in_hours = 24
  device_name             = "AmazonChime"
  media_type              = "video/h264" # Standard for Chime media streaming
}

# 3. Create an IAM Role for Chime to access Kinesis
resource "aws_iam_role" "chime_streaming_role" {
  name = "ChimeStreamingToKinesisRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach policy to allow Chime to write to Kinesis Video Streams
resource "aws_iam_role_policy" "chime_kinesis_policy" {
  name = "ChimeKinesisStreamingPolicy"
  role = aws_iam_role.chime_streaming_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesisvideo:PutMedia",
          "kinesisvideo:UpdateDataRetention",
          "kinesisvideo:DescribeStream",
          "kinesisvideo:CreateStream"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_video_stream.media_stream.arn
      }
    ]
  })
}

# 5. Configure Streaming on the Voice Connector
resource "aws_chime_voice_connector_streaming" "default" {
  voice_connector_id = aws_chime_voice_connector.main.id
  data_retention     = 24
  streaming_disabled = false

  media_streaming_configuration {
    data_retention = 24
    disabled       = false
  }

  # This resource links the Voice Connector to the Kinesis ecosystem via the service role
  # Note: Chime automatically streams to KinesisVideo based on the configuration above.
}

# Output the Voice Connector ID for reference
output "voice_connector_id" {
  value = aws_chime_voice_connector.main.id
}

output "kinesis_video_stream_arn" {
  value = aws_kinesis_video_stream.media_stream.arn
}
```

