# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the Redshift Subnet Group (enabling reachability across subnets)
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [var.subnet_id_1, var.subnet_id_2]

  tags = {
    Environment = "production"
  }
}

# 2. Define a Security Group to allow access to the cluster endpoint
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound access to Redshift"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Narrow this down to your specific network for security
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8CharactersMin1" # Use secrets management in production
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Assign the subnet group containing both subnets
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name

  # Assign the security group
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # Ensure the cluster is accessible if the subnets are public
  publicly_accessible = true 

  skip_final_snapshot = true
}

# Variables used in the configuration
variable "vpc_id" {
  type        = string
  description = "The ID of the VPC"
}

variable "subnet_id_1" {
  type        = string
  description = "The first subnet ID"
}

variable "subnet_id_2" {
  type        = string
  description = "The second subnet ID"
}

# Output the cluster endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

