```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic for notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-event-notifications"
}

# 2. Create an SNS Topic Policy to allow Redshift to publish events
resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.redshift_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid      = "AllowRedshiftToPublish"
        Effect   = "Allow"
        Principal = {
          Service = "events.redshift.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.redshift_notifications.arn
      }
    ]
  })
}

# 3. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier  = "tf-redshift-cluster"
  database_name       = "mydb"
  master_username     = "adminuser"
  master_password     = "MustBe8To64Chars1!"
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  skip_final_snapshot = true
}

# 4. Create the Redshift Event Subscription
resource "aws_redshift_event_subscription" "example" {
  name             = "redshift-event-sub"
  sns_topic_arn    = aws_sns_topic.redshift_notifications.arn
  source_type      = "cluster"
  source_ids       = [aws_redshift_cluster.example.id]
  severity         = "INFO"
  event_categories = [
    "management",
    "monitoring",
    "security"
  ]
}

# Output the SNS Topic ARN
output "sns_topic_arn" {
  value = aws_sns_topic.redshift_notifications.arn
}

# Output the Redshift Cluster Endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}
```

