extracted_code:
# Terraform configuration to set up an AWS S3 bucket for website image storage
# It includes the bucket, public access settings, and a bucket policy to allow public reads.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Random suffix to ensure globally unique bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# 2. S3 Bucket for image storage
resource "aws_s3_bucket" "image_storage" {
  bucket = "website-images-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "Website Image Storage"
    Environment = "Production"
  }
}

# 3. Disable Block Public Access settings to allow public read policy
resource "aws_s3_bucket_public_access_block" "public_access" {
  bucket = aws_s3_bucket.image_storage.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Bucket Policy to allow public GET requests for images
resource "aws_s3_bucket_policy" "public_read_policy" {
  # Depends on public access block being disabled first
  depends_on = [aws_s3_bucket_public_access_block.public_access]
  bucket     = aws_s3_bucket.image_storage.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.image_storage.arn}/*"
      },
    ]
  })
}

# 5. CORS configuration so the images can be fetched from your website domain
resource "aws_s3_bucket_cors_configuration" "cors" {
  bucket = aws_s3_bucket.image_storage.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET"]
    allowed_origins = ["*"] # In production, replace "*" with your specific website domain
    max_age_seconds = 3000
  }
}

output "bucket_name" {
  value = aws_s3_bucket.image_storage.id
}

output "bucket_domain_name" {
  value = aws_s3_bucket.image_storage.bucket_regional_domain_name
}

