# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# The source bucket to be monitored
resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

# A separate bucket (or the same) to store the inventory reports
# Note: AWS recommends a separate bucket for security/organization
resource "aws_s3_bucket" "inventory_reports" {
  bucket = "mybucket-inventory-reports"
}

# The S3 Bucket Inventory configuration
resource "aws_s3_bucket_inventory" "daily_inventory" {
  bucket = aws_s3_bucket.mybucket.id
  name   = "DailyInventoryReport"

  included_object_versions = "All"

  schedule {
    frequency = "Daily"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory_reports.arn
      prefix     = "reports"
    }
  }

  optional_fields = ["Size", "LastModifiedDate", "StorageClass", "ETag"]
}

# Bucket policy to allow S3 to write inventory reports to the destination bucket
resource "aws_s3_bucket_policy" "allow_inventory_writing" {
  bucket = aws_s3_bucket.inventory_reports.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowInventoryCSVGeneration"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory_reports.arn}/reports/*"
        Condition = {
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.mybucket.arn
          }
          StringEquals = {
            "aws:SourceAccount" = "YOUR_ACCOUNT_ID" # Replace with your actual AWS Account ID
          }
        }
      }
    ]
  })
}

