  included_object_versions = "All"

  schedule {
    frequency = "Weekly"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory_bucket.arn
      prefix     = "inventory-reports"
    }
  }

  optional_fields = [
    "Size",
    "LastModifiedDate",
    "StorageClass",
    "ETag",
    "IsMultipartUpload"
  ]
}

# Helper to get current account ID
data "aws_caller_identity" "current" {}
