# Terraform configuration to provision an S3 bucket with KMS server-side encryption

provider "aws" {
  region = "us-east-1"
}

# 1. Create a KMS key for S3 encryption
resource "aws_kms_key" "s3_kms_key" {
  description             = "KMS key for S3 bucket encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

# 2. Create an alias for the KMS key
resource "aws_kms_alias" "s3_kms_key_alias" {
  name          = "alias/s3-encryption-key"
  target_key_id = aws_kms_key.s3_kms_key.key_id
}

# 3. Create the S3 bucket
resource "aws_s3_bucket" "encrypted_bucket" {
  bucket = "my-secure-kms-encrypted-bucket-12345"
}

# 4. Configure the bucket to use the KMS key for Default Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "kms_encryption" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.s3_kms_key.arn
      sse_algorithm     = "aws:kms"
    }
    bucket_key_enabled = true
  }
}

# 5. Optional: Block public access (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "block_public" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

