# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define the S3 Bucket name as a variable for reusability
variable "bucket_name" {
  description = "The name of the S3 bucket"
  type        = string
  default     = "my-terraform-static-website-example-12345"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "website_bucket" {
  bucket = var.bucket_name
}

# 2. Configure Public Access Block (Allows public policy)
resource "aws_s3_bucket_public_access_block" "website_bucket_access" {
  bucket = aws_s3_bucket.website_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 3. Configure the bucket for Static Website Hosting
resource "aws_s3_bucket_website_configuration" "website_config" {
  bucket = aws_s3_bucket.website_bucket.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# 4. Define a Bucket Policy to allow public read access (Required for website hosting)
resource "aws_s3_bucket_policy" "allow_public_access" {
  # Wait for public access block to be disabled before applying policy
  depends_on = [aws_s3_bucket_public_access_block.website_bucket_access]
  bucket     = aws_s3_bucket.website_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_bucket.arn}/*"
      },
    ]
  })
}

# 5. Optional: Create index.html object
resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.website_bucket.id
  key          = "index.html"
  content      = "<html><body><h1>Hello from Terraform AI</h1></body></html>"
  content_type = "text/html"
}

# Output the website endpoint URL
output "website_url" {
  value       = aws_s3_bucket_website_configuration.website_config.website_endpoint
  description = "The URL of the static website"
}

