  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "static_site" {
  bucket = "my-terraform-static-website-bucket-unique-id"
}

# 2. Configure the Website definition
resource "aws_s3_bucket_website_configuration" "static_site_config" {
  bucket = aws_s3_bucket.static_site.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# 3. Disable Public Access Block (Required for public website hosting)
resource "aws_s3_bucket_public_access_block" "static_site_access" {
  bucket = aws_s3_bucket.static_site.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Create a Bucket Policy to allow public read access
resource "aws_s3_bucket_policy" "allow_public_access" {
  # Wait for the public access block to be disabled before applying policy
  depends_on = [aws_s3_bucket_public_access_block.static_site_access]
  bucket     = aws_s3_bucket.static_site.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.static_site.arn}/*"
      },
    ]
  })
}

# Output the Website Endpoint URL
output "website_url" {
  value       = aws_s3_bucket_website_configuration.static_site_config.website_endpoint
  description = "The URL of the static website"
}

reference:
resource "aws_s3_bucket" "example" {
  bucket = "mybucket"
}

resource "aws_s3_bucket_website_configuration" "example" {
  bucket = aws_s3_bucket.example.id

  index_document {
    suffix = "index.html"
  }
}

