extracted_code:
# Terraform configuration for an Autograding System using AWS CodeBuild and S3

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Buckets for Storage
resource "aws_s3_bucket" "grading_artifacts" {
  bucket        = "cs-course-grading-artifacts"
  force_destroy = true
}

resource "aws_s3_bucket" "grading_logs" {
  bucket        = "cs-course-grading-logs"
  force_destroy = true
}

# 2. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.grading_artifacts.arn,
          "${aws_s3_bucket.grading_artifacts.arn}/*",
          aws_s3_bucket.grading_logs.arn,
          "${aws_s3_bucket.grading_logs.arn}/*"
        ]
      }
    ]
  })
}

# 3. CodeBuild Project (The Grader)
resource "aws_codebuild_project" "autograder" {
  name          = "student-autograder"
  description   = "Executes student code from GitHub and records results"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.grading_artifacts.bucket
    name      = "grading-results"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "COURSE_ID"
      value = "CS101"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/student-org/assignment-repo.git"
    git_clone_depth = 1
    # The buildspec defines the grading logic (e.g., run pytest, make, etc.)
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
        pre_build:
          commands:
            - echo "Preparing environment..."
        build:
          commands:
            - echo "Running Student Tests..."
            - python3 grader_script.py > results.json
        post_build:
          commands:
            - echo "Grading complete."
      artifacts:
        files:
          - results.json
          - logs/*.log
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      status      = "ENABLED"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_logs.id}/build-log"
    }
  }
}

# 4. Webhook for Automatic Triggering on GitHub Push
# Note: Requires GitHub OAuth Token to be configured in AWS CodeBuild manually or via secret
resource "aws_codebuild_webhook" "github_trigger" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$"
    }
  }
}

# 5. SNS Topic for Grading Notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "grading-status-topic"
}

resource "aws_iam_role" "eventbridge_role" {
  name = "autograding-eventbridge-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
      }
    ]
  })
}

# 6. EventBridge Rule to notify when grading finishes
resource "aws_cloudwatch_event_rule" "grading_complete" {
  name        = "grading-complete-rule"
  description = "Trigger notification when CodeBuild finishes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      "build-status" = ["SUCCEEDED", "FAILED", "STOPPED"]
      "project-name" = [aws_codebuild_project.autograder.name]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns_target" {
  rule      = aws_cloudwatch_event_rule.grading_complete.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.grading_notifications.arn
}

resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.grading_notifications.arn
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "sns:Publish"
        Effect   = "Allow"
        Resource = aws_sns_topic.grading_notifications.arn
        Principal = {
          Service = "events.amazonaws.com"
        }
      }
    ]
  })
}

