        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for CodeBuild (Logging and S3 Access)
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.grading_outputs.arn,
          "${aws_s3_bucket.grading_outputs.arn}/*"
        ]
      }
    ]
  })
}

# 4. CodeBuild Project for Autograding
resource "aws_codebuild_project" "autograder" {
  name          = "cs-student-autograder"
  description   = "Executes student submissions and saves scores to S3"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.grading_outputs.bucket
    packaging = "NONE"
    name      = "grading-results"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_S3_BUCKET"
      value = aws_s3_bucket.grading_outputs.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submission-repo.git"
    git_clone_depth = 1

    # The buildspec defines how the grading script runs
    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo "Installing grading dependencies..."
      - pip install -r requirements-grader.txt
  build:
    commands:
      - echo "Running Autograder..."
      - python run_tests.py > results.json
  post_build:
    commands:
      - echo "Uploading results..."
      - aws s3 cp results.json s3://$GRADING_S3_BUCKET/results/submission_$CODEBUILD_RESOLVED_SOURCE_VERSION.json
artifacts:
  files:
    - results.json
EOF
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "grading-logs"
    }
  }
}

# 5. Output the S3 Bucket Name
output "s3_bucket_name" {
  value       = aws_s3_bucket.grading_outputs.id
  description = "The name of the S3 bucket where grading outputs are stored."
}

