# Terraform configuration for an Autograding System with isolated AWS CodeBuild

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Isolation - VPC with no Internet Gateway
resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags                 = { Name = "autograding-isolated-vpc" }
}

resource "aws_subnet" "grading_subnet" {
  vpc_id            = aws_vpc.grading_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags              = { Name = "grading-private-subnet" }
}

# Security Group to block all egress by default
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-grading-sg"
  description = "Security group for isolated grading containers"
  vpc_id      = aws_vpc.grading_vpc.id

  # No egress rules defined here mean zero outbound traffic (including internet)
}

# 2. Storage for Grading Outcomes and Scripts
resource "aws_s3_bucket" "grading_results" {
  bucket        = "cs-course-grading-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 3. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "grading-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "codebuild.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Effect   = "Allow"
        Resource = "*"
      },
      {
        Action   = ["s3:PutObject", "s3:GetObject"]
        Effect   = "Allow"
        Resource = ["${aws_s3_bucket.grading_results.arn}/*"]
      },
      {
        Action   = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# 4. CodeBuild Project for Grading
resource "aws_codebuild_project" "autograder" {
  name          = "student-submission-autograder"
  description   = "Executes student code in an isolated environment"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo-placeholder.git"
    git_clone_depth = 1
    buildspec       = "buildspec-grading.yml"
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.grading_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Environment = "Production"
    Subject     = "ComputerScience"
  }
}

# Webhook to trigger on student push events
resource "aws_codebuild_webhook" "github_trigger" {
  project_name = aws_codebuild_project.autograder.name
  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
  }
}

