# Terraform configuration for an Autograding System
# Components: VPC (Isolated), S3 (Storage), CodeBuild (Execution), IAM (Permissions)

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Layer: Isolated VPC with no Internet Gateway
resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "autograding-isolated-vpc" }
}

resource "aws_subnet" "private_grading_subnet" {
  vpc_id            = aws_vpc.grading_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = { Name = "autograding-private-subnet" }
}

# Security Group to block all outbound traffic except internal needs
resource "aws_security_group" "codebuild_sg" {
  name        = "grading-execution-sg"
  description = "Restrict internet access for student code"
  vpc_id      = aws_vpc.grading_vpc.id

  # No egress rules defined = Default Deny All Outbound
  # Allows the environment to be truly "Air-gapped" from the public web
}

# VPC Gateways for S3 and Logs (Standard CodeBuild requirements in VPC)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.grading_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_vpc.grading_vpc.main_route_table_id]
}

# 2. Storage: S3 Buckets for Artifacts and Grading Output
resource "aws_s3_bucket" "grading_output" {
  bucket = "cs-course-autograding-results-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 3. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "codebuild.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = ["s3:PutObject", "s3:GetObject", "s3:GetBucketLocation"]
        Resource = ["${aws_s3_bucket.grading_output.arn}", "${aws_s3_bucket.grading_output.arn}/*"]
      },
      {
        Effect   = "Allow"
        Action   = ["ec2:CreateNetworkInterface", "ec2:DescribeNetworkInterfaces", "ec2:DeleteNetworkInterface", "ec2:DescribeSubnets", "ec2:DescribeSecurityGroups", "ec2:DescribeVpcs"]
        Resource = "*"
      }
    ]
  })
}

# 4. CodeBuild Project: The Execution Environment
resource "aws_codebuild_project" "autograder" {
  name           = "cs-student-autograder"
  description    = "Executes student submissions in an isolated VPC"
  build_timeout  = "5"
  service_role   = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.grading_output.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submission-repo.git"
