    # buildspec defined here or in the repo
    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo "Installing dependencies..."
  build:
    commands:
      - echo "Running student tests..."
      - python3 grader_script.py > results.json
  post_build:
    commands:
      - aws s3 cp results.json s3://$RESULT_BUCKET/results-$CODEBUILD_BUILD_ID.json
EOF
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.private_grading_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Environment = "Production"
    Subject     = "ComputerScience"
  }
}

