```hcl
# Terraform configuration for an AWS-based Autograding System
# This setup uses CodeBuild within a private VPC to execute student code with NO outbound internet access.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags                 = { Name = "autograding-vpc" }
}

resource "aws_subnet" "isolated_grading_subnet" {
  vpc_id            = aws_vpc.grading_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags              = { Name = "grading-isolated-subnet" }
}

# Security Group to block all egress (Outbound) - Specifically for student code execution
resource "aws_security_group" "grading_sg" {
  name        = "grading-engine-sg"
  description = "Block all outbound traffic for student code execution"
  vpc_id      = aws_vpc.grading_vpc.id

  # No egress rules defined = Default Deny all outbound
  # Inbound only from within the VPC if internal communication is needed
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }
}

# --- Storage ---
resource "aws_s3_bucket" "grading_artifacts" {
  bucket        = "autograding-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# --- IAM Roles ---
resource "aws_iam_role" "codebuild_role" {
  name = "grading-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "codebuild.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# --- CodeBuild Project ---
resource "aws_codebuild_project" "autograder" {
  name           = "student-autograder"
  description    = "Executes student submissions in an isolated environment"
  service_role   = aws_iam_role.codebuild_role.arn
  build_timeout  = "5"

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.grading_artifacts.bucket
    name     = "grading-outputs"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_MODE"
      value = "STRICT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/organization/student-repo.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting isolated grading environment..."
        build:
          commands:
            - ./grade.sh
      artifacts:
        files:
          - 'results.json'
          - 'logs/**/*'
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.isolated_grading_subnet.id]
    security_group_ids = [aws_security_group.grading_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      stream_name = "grading-task"
    }
  }
}
```

