```hcl
# Terraform configuration for a Cat Image Web Application
# Hosted using AWS S3 for storage/static hosting and API Gateway for the endpoint

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- S3 Bucket for Cat Images ---

resource "aws_s3_bucket" "cat_images" {
  bucket_prefix = "cat-images-app-"
  force_destroy = true
}

resource "aws_s3_bucket_public_access_block" "cat_images_access" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Allow public reads for serving images
resource "aws_s3_bucket_policy" "allow_public_read" {
  depends_on = [aws_s3_bucket_public_access_block.cat_images_access]
  bucket     = aws_s3_bucket.cat_images.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.cat_images.arn}/*"
      },
    ]
  })
}

# --- IAM Role for API Gateway to write to S3 ---

resource "aws_iam_role" "api_gateway_s3_role" {
  name = "api_gateway_s3_upload_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "apigateway.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "s3_policy" {
  name = "s3_write_policy"
  role = aws_iam_role.api_gateway_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetObject", "s3:ListBucket"]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      }
    ]
  })
}

# --- API Gateway REST API ---

resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI"
  description = "API to upload and retrieve cat images directly via S3 integration"

  binary_media_types = ["image/jpeg", "image/png", "image/gif"]
}

# Resource: /upload/{item}
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "item_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_resource.upload_resource.id
  path_part   = "{item}"
}

# PUT Method for uploading images
resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.item_resource.id
  http_method   = "PUT"
  authorization = "NONE"

  request_parameters = {
    "method.request.path.item" = true
  }
}

# S3 Integration for Upload
resource "aws_api_gateway_integration" "s3_upload_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.item_resource.id
  http_method             = aws_api_gateway_method.upload_method.http_method
  integration_http_method = "PUT"
  type                    = "AWS"
  uri                     = "arn:aws:apigateway:${data.aws_region.current.name}:s3:path/${aws_s3_bucket.cat_images.id}/{item}"
  credentials             = aws_iam_role.api_gateway_s3_role.arn

  request_parameters = {
    "integration.request.path.item" = "method.request.path.item"
  }
}

resource "aws_api_gateway_method_response" "200" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.item_resource.id
  http_method = aws_api_gateway_method.upload_method.http_method
  status_code = "200"
}

resource "aws_api_gateway_integration_response" "s3_upload_response" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.item_resource.id
  http_method = aws_api_gateway_method.upload_method.http_method
  status_code = aws_api_gateway_method_response.200.status_code

  depends_on = [aws_api_gateway_integration.s3_upload_integration]
}

# --- Deployment ---

resource "aws_api_gateway_deployment" "cat_api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  depends_on = [
    aws_api_gateway_integration.s3_upload_integration,
    aws_api_gateway_integration_response.s3_upload_response
  ]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api_deployment.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# --- Helpers ---

data "aws_region" "current" {}

output "upload_url" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/upload"
  description = "Base URL for uploading images. Append filename to the end (e.g. /upload/mycat.jpg)"
}

output "s3_bucket_url" {
  value = "https://${aws_s3_bucket.cat_images.bucket_domain_name}"
  description = "URL to access the stored cat images"
}
```

