terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- DynamoDB Table ---
resource "aws_dynamodb_table" "cats_table" {
  name         = "cats-data"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# --- S3 Bucket ---
resource "aws_s3_bucket" "cat_images" {
  bucket = "caas-cat-images-bucket"
}

# --- IAM Role for Lambdas ---
resource "aws_iam_role" "lambda_exec" {
  name = "caas_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# --- Lambda Functions ---
resource "aws_lambda_function" "get_cat" {
  filename      = "get_cat.zip" # Placeholder for local zip
  function_name = "caas_get_handler"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
}

resource "aws_lambda_function" "put_cat" {
  filename      = "put_cat.zip" # Placeholder for local zip
  function_name = "caas_put_handler"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
}

# --- API Gateway ---
resource "aws_api_gateway_rest_api" "caas_api" {
  name = "caas"
}

resource "aws_api_gateway_resource" "caas_resource" {
  rest_api_id = aws_api_gateway_rest_api.caas_api.id
  parent_id   = aws_api_gateway_rest_api.caas_api.root_resource_id
  path_part   = "cat"
}

# GET Method
resource "aws_api_gateway_method" "get_method" {
  rest_api_id   = aws_api_gateway_rest_api.caas_api.id
  resource_id   = aws_api_gateway_resource.caas_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "get_integration" {
  rest_api_id             = aws_api_gateway_rest_api.caas_api.id
  resource_id             = aws_api_gateway_resource.caas_resource.id
  http_method             = aws_api_gateway_method.get_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.get_cat.invoke_arn
}

# PUT Method
resource "aws_api_gateway_method" "put_method" {
  rest_api_id   = aws_api_gateway_rest_api.caas_api.id
  resource_id   = aws_api_gateway_resource.caas_resource.id
  http_method   = "PUT"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "put_integration" {
  rest_api_id             = aws_api_gateway_rest_api.caas_api.id
  resource_id             = aws_api_gateway_resource.caas_resource.id
  http_method             = aws_api_gateway_method.put_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.put_cat.invoke_arn
}

# --- Lambda Permissions for API Gateway ---
resource "aws_lambda_permission" "allow_api_get" {
  statement_id  = "AllowExecutionFromAPIGatewayGET"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.caas_api.execution_arn}/*/${aws_api_gateway_method.get_method.http_method}${aws_api_gateway_resource.caas_resource.path}"
}

resource "aws_lambda_permission" "allow_api_put" {
  statement_id  = "AllowExecutionFromAPIGatewayPUT"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.put_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.caas_api.execution_arn}/*/${aws_api_gateway_method.put_method.http_method}${aws_api_gateway_resource.caas_resource.path}"
}

# --- Deployment ---
resource "aws_api_gateway_deployment" "caas_deployment" {
  depends_on = [
    aws_api_gateway_integration.get_integration,
    aws_api_gateway_integration.put_integration
  ]
  rest_api_id = aws_api_gateway_rest_api.caas_api.id
  stage_name  = "prod"
}
