# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. SSH Key Pair
resource "aws_key_pair" "main" {
  key_name   = "ec2-backup-key"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQD3F6ty..." # Replace with your actual public key
}

# 2. EC2 Instance
resource "aws_instance" "web_server" {
  ami           = "ami-0c7217cdde317cfec" # Amazon Linux 2023 AMI (Region specific)
  instance_type = "t3.micro"
  key_name      = aws_key_pair.main.key_name

  tags = {
    Name   = "Managed-EC2-Instance"
    Backup = "Daily"
  }
}

# 3. AWS Backup Vault
resource "aws_backup_vault" "main_vault" {
  name = "daily-backup-vault"
}

# 4. AWS Backup Plan
resource "aws_backup_plan" "daily_plan" {
  name = "daily-ec2-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.main_vault.name
    schedule          = "cron(0 0 * * ? *)" # Runs daily at 12:00 AM UTC

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# 5. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 6. AWS Backup Selection (Assigning the EC2 instance to the plan)
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily-ec2-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "Daily"
  }
}
