# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lambda execution
resource "aws_iam_role" "iam_for_lambda" {
  name = "daily_job_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Add CloudWatch Logs permissions to the Lambda
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Lambda Function containing the code to execute
resource "aws_lambda_function" "daily_scheduled_lambda" {
  filename      = "lambda_function_payload.zip" # Ensure this file exists locally
  function_name = "daily_scheduled_job"
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      JOB_NAME = "DailyMorningTask"
    }
  }
}

# 4. EventBridge Schedule Rule (Daily at 07:00 UTC)
resource "aws_cloudwatch_event_rule" "daily_seven_am" {
  name                = "daily-seven-am-utc"
  description         = "Triggers at 07:00 UTC every day"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 5. EventBridge Target (Pointing to the Lambda Function)
resource "aws_cloudwatch_event_target" "run_lambda_daily" {
  rule      = aws_cloudwatch_event_rule.daily_seven_am.name
  target_id = "TriggerLambdaDaily"
  arn       = aws_lambda_function.daily_scheduled_lambda.arn
}

# 6. Lambda Permission to allow EventBridge to invoke the function
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_scheduled_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_seven_am.arn
}

