    }]
  })
}

# Attach basic execution policy to the role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam:aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Sample Lambda Function code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"
  source {
    content  = "exports.handler = async (event) => { console.log('Job processed'); };"
    filename = "index.js"
  }
}

# The Lambda Function
resource "aws_lambda_function" "daily_job" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "daily_0700_worker"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# EventBridge Rule: Trigger every day at 07:00 UTC
resource "aws_cloudwatch_event_rule" "daily_trigger" {
  name                = "trigger-lambda-daily-0700"
  description         = "Triggers Lambda every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge Target: Link Rule to Lambda
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_trigger.name
  target_id = "DailyLambdaTarget"
  arn       = aws_lambda_function.daily_job.arn
}

# Lambda Permission: Allow EventBridge to invoke the Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_job.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_trigger.arn
}

