# Terraform configuration for a globally distributed video streaming platform
# using Amazon S3 for storage and AWS CloudFront for content delivery.

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Video Assets
resource "aws_s3_bucket" "video_storage" {
  bucket = "global-video-streaming-assets-${random_id.suffix.hex}"

  tags = {
    Name        = "Video Content Storage"
    Environment = "Production"
  }
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. Block Public Access to S3 (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "video_storage_block" {
  bucket = aws_s3_bucket.video_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 3. CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "video_streaming_oac"
  description                       = "Allow CloudFront to access S3 video content"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 4. CloudFront Distribution for Global Delivery
resource "aws_cloudfront_distribution" "video_cdn" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global Video Streaming CDN"
  default_root_object = "index.html"

  origin {
    domain_name              = aws_s3_bucket.video_storage.bucket_regional_domain_name
    origin_id                = "S3-VideoStorage"
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-VideoStorage"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  price_class = "PriceClass_All" # Deploy to all global edge locations

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Project = "VideoStreaming"
  }
}

# 5. S3 Bucket Policy to allow CloudFront Access
resource "aws_s3_bucket_policy" "allow_cloudfront" {
  bucket = aws_s3_bucket.video_storage.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid      = "AllowCloudFrontServicePrincipalReadOnly"
        Effect   = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_storage.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_cdn.arn
          }
        }
      }
    ]
  })
}

# Outputs
output "cloudfront_domain_name" {
  value       = aws_cloudfront_distribution.video_cdn.domain_name
  description = "The domain name of the CloudFront distribution for accessing video content globally."
}

output "s3_bucket_name" {
  value       = aws_s3_bucket.video_storage.id
  description = "The name of the S3 bucket where video files should be uploaded."
}

