# Terraform configuration for a globally distributed video streaming platform
# using Amazon S3 for storage and AWS CloudFront for content delivery.

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Video Assets
resource "aws_s3_bucket" "video_storage" {
  bucket = "global-video-streaming-assets-${random_id.suffix.hex}"

  tags = {
    Name        = "Video Content Storage"
    Environment = "Production"
  }
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. Block Public Access to S3 (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "video_storage_block" {
  bucket = aws_s3_bucket.video_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 3. CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "video_streaming_oac"
  description                       = "Allow CloudFront to access S3 video content"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 4. CloudFront Distribution for Global Delivery
resource "aws_cloudfront_distribution" "video_cdn" {
