# Terraform configuration for a globally distributed video streaming platform
# Services used: S3 (Origin), CloudFront (CDN), Route 53 (DNS), ACM (SSL/TLS), Lambda@Edge (Auth/Header manipulation)

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # ACM certificates for CloudFront must be in us-east-1
}

# --- S3 Storage for Video Assets ---
resource "aws_s3_bucket" "video_assets" {
  bucket = "global-video-streaming-platform-assets"
}

resource "aws_s3_bucket_public_access_block" "video_assets_block" {
  bucket                  = aws_s3_bucket.video_assets.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# --- CloudFront Origin Access Control (OAC) ---
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "video_oac"
  description                       = "OAC for video streaming content"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# --- ACM Certificate (Assumes domain is managed in Route 53) ---
resource "aws_acm_certificate" "cert" {
  domain_name       = "stream.example.com"
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

# --- CloudFront Distribution ---
resource "aws_cloudfront_distribution" "video_dist" {
  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"
  price_class         = "PriceClass_All" # Global distribution

  aliases = ["stream.example.com"]

  origin {
    domain_name              = aws_s3_bucket.video_assets.bucket_regional_domain_name
    origin_id                = "S3-Video-Origin"
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-Video-Origin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate.cert.arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  tags = {
    Environment = "production"
    Application = "video-streaming"
  }
}

# --- S3 Bucket Policy to allow CloudFront OAC ---
resource "aws_s3_bucket_policy" "allow_cloudfront" {
  bucket = aws_s3_bucket.video_assets.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "s3:GetObject"
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.video_assets.arn}/*"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_dist.arn
          }
        }
      }
    ]
  })
}

# --- Route 53 DNS Configuration ---
data "aws_route53_zone" "selected" {
  name = "example.com"
}

resource "aws_route53_record" "streaming_alias" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "stream.example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_dist.domain_name
    zone_id                = aws_cloudfront_distribution.video_dist.hosted_zone_id
    evaluate_target_health = false
  }
}

# --- WAF for Security ---
resource "aws_wafv2_web_acl" "waf" {
  name     = "video-platform-waf"
  scope    = "CLOUDFRONT"
  provider = aws 

  default_action {
    allow {}
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "videoPlatformWAF"
    sampled_requests_enabled   = true
  }

  rule {
    name     = "AWSManagedRulesCommonRuleSet"
    priority = 1

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesCommonRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "CommonRuleSet"
      sampled_requests_enabled   = true
    }
  }
}

