}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = { Name = "rds-private-subnet-a" }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = { Name = "rds-private-subnet-b" }
}

# DB Subnet Group
resource "aws_db_subnet_group" "rds_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = { Name = "RDS Private Subnet Group" }
}

# --- Security & Encryption ---

# KMS Customer Managed Key for Database Encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS Key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = { Name = "rds-encryption-key" }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Security group for PostgreSQL RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restrict access to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Database Configuration ---

# Custom PostgreSQL Parameter Group
resource "aws_db_parameter_group" "postgres_pg" {
  name   = "custom-postgres15-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }
}

# Protected PostgreSQL RDS Instance
resource "aws_db_instance" "postgresql" {
  identifier        = "protected-postgres-db"
  engine            = "postgres"
  engine_version    = "15.4"
  instance_class    = "db.t3.medium"
  allocated_storage = 50
  storage_type      = "gp3"

  # High Availability & Multi-AZ
  multi_az = true

  # Credentials (Use AWS Secrets Manager in production)
  db_name  = "myappdb"
  username = "dbadmin"
  password = "SensitivePassword123!" # Placeholder

  # Network & Security
  db_subnet_group_name   = aws_db_subnet_group.rds_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_key.arn

  # Parameter Group
  parameter_group_name = aws_db_parameter_group.postgres_pg.name

  # Backup & Maintenance
  backup_retention_period = 7
  skip_final_snapshot     = false
  deletion_protection     = true

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

