resource "aws_db_parameter_group" "postgresql_params" {
  name   = "rds-postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }
}

# 4. Security Group for Database Access
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgresql-sg"
  description = "Allow inbound traffic to PostgreSQL"
  vpc_id      = "vpc-12345678" # Replace with actual VPC ID

