  identifier        = "protected-postgres-db"
  engine            = "postgres"
  engine_version    = "15.4"
  instance_class    = "db.t3.micro"
  allocated_storage = 20
  storage_type      = "gp3"

  # Security and High Availability
  multi_az               = true
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_key.arn
