# Terraform configuration for AWS RDS PostgreSQL 15 in Public Subnets
# Purpose: Airbyte connector testing (Managed, Low-maintenance)

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Networking
resource "aws_vpc" "airbyte_test_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "airbyte-test-vpc" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.airbyte_test_vpc.id
}

resource "aws_subnet" "public_1" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_test_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public_rt.id
}

# 2. Security Group (Allowing external access for testing)
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg"
  description = "Allow inbound traffic for Airbyte testing"
  vpc_id      = aws_vpc.airbyte_test_vpc.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Recommendation: Restrict to specific Airbyte IPs in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. RDS Infrastructure
resource "aws_db_subnet_group" "test_subnets" {
  name       = "airbyte-test-subnets"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]
}

resource "aws_db_instance" "airbyte_pg_test" {
  identifier           = "airbyte-test-db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp3"
  db_name              = "airbyte_test"
  username             = "airbyte_user"
  password             = "ChangeMe123!" # Ideally use a secret manager

  publicly_accessible  = true
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.test_subnets.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Low-maintenance configuration
  auto_minor_version_upgrade = true
  maintenance_window         = "Mon:00:00-Mon:03:00"
  backup_retention_period    = 7
  performance_insights_enabled = true

  tags = {
    Environment = "Testing"
    Project     = "AirbyteConnectors"
  }
}

output "db_endpoint" {
  value = aws_db_instance.airbyte_pg_test.endpoint
}

