  region = "us-east-1"
}

# Networking - Security Group to allow PostgreSQL traffic
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-test-rds-sg"
  description = "Allow inbound traffic for Airbyte testing"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Scoped to public for testing; narrow this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Subnet Group for the RDS instance using designated public subnets
resource "aws_db_subnet_group" "rds_public_group" {
  name       = "airbyte-public-subnet-group"
  subnet_ids = ["subnet-xxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyy"] # Replace with actual public subnet IDs

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

# RDS PostgreSQL Instance
