  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  publicly_accessible = true
  skip_final_snapshot = true        # Disabled as per request for low-maintenance/testing
  apply_immediately   = true        # Modifications take effect right away

  # Low-maintenance settings
  auto_minor_version_upgrade  = true
  backup_retention_period     = 0   # No backups needed for ephemeral testing
  deletion_protection         = false

  tags = {
    Environment = "Testing"
    Tool        = "Airbyte"
  }
}

output "rds_endpoint" {
  value = aws_db_instance.airbyte_test_db.endpoint
}
