  route_table_id = aws_route_table.public_rt.id
}

# 5. Security Group permitting database traffic (MySQL 3306)
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow MySQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Open for public access as requested
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 6. RDS Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "My DB subnet group"
  }
}

# 7. RDS MySQL 5.7 Instance
resource "aws_db_instance" "mysql_db" {
  allocated_storage      = 500
  engine                 = "mysql"
  engine_version         = "5.7"
  instance_class         = "db.t3.medium"
  db_name                = "mydatabase"
  username               = "admin"
  password               = "password123" # In production, use sensitivity variables or secret managers
  parameter_group_name   = "default.mysql5.7"
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true

  tags = {
    Name = "MySQL-5.7-Instance"
  }
}

# 8. Output Database Endpoint
output "database_endpoint" {
  description = "The connection endpoint for the RDS instance"
  value       = aws_db_instance.mysql_db.endpoint
}

