# Terraform configuration for AWS RDS MySQL with Random Password and Public Access

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the RDS instance
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Security Group to allow public access to MySQL (Port 3306)
resource "aws_security_group" "rds_public_sg" {
  name        = "rds-public-access-sg"
  description = "Allow inbound traffic on port 3306 from anywhere"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS MySQL Instance
resource "aws_db_instance" "mysql_instance" {
  identifier           = "terraform-mysql-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage     = 20
  storage_type         = "gp2"
  db_name              = "mydatabase"
  username             = "admin"
  password             = random_password.db_password.result
  parameter_group_name = "default.mysql8.0"

  # Enabling Public Access
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.rds_public_sg.id]
  skip_final_snapshot    = true

  tags = {
    Name = "Terraform-MySQL-Public"
  }
}

# Output the DB Endpoint and Password
output "db_endpoint" {
  value = aws_db_instance.mysql_instance.endpoint
}

output "db_password" {
  value     = random_password.db_password.result
  sensitive = true
}

