  region = "us-east-1"
}

# Generate a random password for the DB root user
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Security Group to allow public access (Note: Ensure the DB is in a public subnet)
resource "aws_security_group" "rds_public_access" {
  name        = "rds-public-access-sg"
  description = "Security group for RDS allowing public MySQL access"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS MySQL Instance
resource "aws_db_instance" "mysql_instance" {
  allocated_storage      = 20
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  identifier             = "mysqldb-instance"
  db_name                = "applicationdb"
  username               = "admin"
  password               = random_password.db_password.result
  parameter_group_name   = "default.mysql8.0"

  # Public Access configuration
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.rds_public_access.id]

  # Deletion safeguards
  skip_final_snapshot    = false
  final_snapshot_identifier = "mysqldb-instance-final-snapshot"
  deletion_protection    = false

  tags = {
    Name = "Terraform-MySQL-Instance"
  }
}

# Output the connection endpoint and password
output "db_endpoint" {
  value = aws_db_instance.mysql_instance.endpoint
}

output "db_password" {
  value     = random_password.db_password.result
  sensitive = true
}

