# Terraform configuration for an AWS RDS PostgreSQL instance in a custom VPC

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-postgresql-vpc"
  }
}

resource "aws_subnet" "db_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-subnet-1"
  }
}

resource "aws_subnet" "db_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-subnet-2"
  }
}

# 2. RDS Subnet Group (Required for multi-AZ or specific subnet placement)
resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.db_subnet_1.id, aws_subnet.db_subnet_2.id]

  tags = {
    Name = "PostgreSQL DB subnet group"
  }
}

# 3. Security Group to allow PostgreSQL traffic
resource "aws_security_group" "rds_sg" {
  name        = "allow_postgresql"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Allow internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. PostgreSQL Instance
resource "aws_db_instance" "postgres_db" {
  identifier           = "terraform-postgresql-instance"
  engine               = "postgres"
  engine_version       = "15.4" # Specific PostgreSQL version
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  db_name              = "myappdb"
  username             = "dbadmin"
  password             = "Password123!" # In production, use Sensitive variables or Secrets Manager
  parameter_group_name = "default.postgres15"

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Environment = "dev"
    ManagedBy   = "Terraform"
  }
}

output "db_endpoint" {
  value = aws_db_instance.postgres_db.endpoint
}

