# AWS PostgreSQL Database Configuration with Custom VPC
# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Networking: Custom VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

# Networking: Subnets in two different AZs (required for DB Subnet Group)
resource "aws_subnet" "db_subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-subnet-a"
  }
}

resource "aws_subnet" "db_subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-subnet-b"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "rds_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.db_subnet_a.id, aws_subnet.db_subnet_b.id]

  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Security Group to allow PostgreSQL traffic
resource "aws_security_group" "db_sg" {
  name        = "rds-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier           = "postgres-instance"
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t3.micro"

  # Storage Configuration
  allocated_storage     = 5
  max_allocated_storage = 50 # Enables Storage Autoscaling
  storage_type          = "gp3"

  # Database Credentials
  db_name              = "myappdb"
  username             = "postgres"
  password             = "ChangeMe123!" # In production, use secret managers (sm/kms)

  # Network and Security
  db_subnet_group_name   = aws_db_subnet_group.rds_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = false
  skip_final_snapshot    = true

  # Maintenance Window (Mondays 12:00 AM to 03:00 AM UTC)
  maintenance_window      = "mon:00:00-mon:03:00"
  backup_window           = "04:00-05:00"
  backup_retention_period = 7

  tags = {
    Environment = "dev"
  }
}
