# Includes SQLSERVER_AUDIT and TDE options

resource "aws_db_option_group" "pike" {
  name                     = "option-group-pike"
  option_group_description = "Option group for sqlserver-ee with SQLSERVER_AUDIT and TDE"
  engine_name              = "sqlserver-ee"
  major_engine_version     = "11.00"

  # Transparent Data Encryption (TDE) Option
  option {
    option_name = "TDE"
  }

  # SQL Server Audit Option
  option {
    option_name = "SQLSERVER_AUDIT"

    # Note: SQLSERVER_AUDIT typically requires settings like an S3 bucket 
    # and an IAM role for it to be fully functional in a real-world scenario.
    option_settings {
      name  = "ENABLE_AUDITING"
      value = "YES"
    }
  }

  tags = {
    Name = "option-group-pike"
  }
}

