  name              = "lightsail-auto-snapshot-node"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "micro_2_0"

  add_on {
    type          = "AutoSnapshot"
    snapshot_time = "06:00" # Time in HH:mm format (UTC)
    status        = "Enabled"
  }
}

