response:
```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create an Amazon Lightsail Instance with Dual-Stack networking
# Note: "dualstack" is the IP address type for enabling both IPv4 and IPv6
resource "aws_lightsail_instance" "dualstack_instance" {
  name              = "terraform-dualstack-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "ubuntu_22_04"
  bundle_id         = "nano_3_0"
  ip_address_type   = "dualstack"

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Optional: Open standard ports in the Lightsail Firewall
resource "aws_lightsail_instance_public_ports" "dualstack_ports" {
  instance_name = aws_lightsail_instance.dualstack_instance.name

  port_info {
    protocol  = "tcp"
    from_port = 22
    to_port   = 22
  }

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }
}

# Output the IP addresses
output "instance_public_ipv4" {
  value       = aws_lightsail_instance.dualstack_instance.public_ip_address
  description = "The public IPv4 address of the Lightsail instance"
}

output "instance_ipv6_addresses" {
  value       = aws_lightsail_instance.dualstack_instance.ipv6_addresses
  description = "The assigned IPv6 addresses of the Lightsail instance"
}
```

