# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "lightsail_bucket" {
  bucket = "my-lightsail-access-bucket-unique-id"
}

# 2. Create an IAM User for Lightsail (Lightsail instances use IAM users/keys for S3 access)
resource "aws_iam_user" "lightsail_user" {
  name = "lightsail-s3-access-user"
}

# 3. Create access keys for the user
resource "aws_iam_access_key" "lightsail_key" {
  user = aws_iam_user.lightsail_user.name
}

# 4. Create a policy allowing access to the S3 bucket
resource "aws_iam_user_policy" "lightsail_s3_policy" {
  name = "lightsail-s3-policy"
  user = aws_iam_user.lightsail_user.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          "${aws_s3_bucket.lightsail_bucket.arn}",
          "${aws_s3_bucket.lightsail_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 5. Create the Lightsail Instance
resource "aws_lightsail_instance" "example" {
  name              = "s3-access-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # Pass the credentials to the instance via user_data (for demonstration)
  # In production, consider using a configuration management tool or secrets manager
  user_data = <<-EOF
              #!/bin/bash
              mkdir -p /home/ec2-user/.aws
              echo "[default]" > /home/ec2-user/.aws/credentials
              echo "aws_access_key_id = ${aws_iam_access_key.lightsail_key.id}" >> /home/ec2-user/.aws/credentials
              echo "aws_secret_access_key = ${aws_iam_access_key.lightsail_key.secret}" >> /home/ec2-user/.aws/credentials
              chown -R ec2-user:ec2-user /home/ec2-user/.aws
              EOF
}

output "instance_public_ip" {
