# Configure the AWS Provider
provider "aws" {
  region = "us-east-1" # Lightsail distributions are often managed via us-east-1
}

# 1. Create a Lightsail Bucket to act as the origin
resource "aws_lightsail_bucket" "origin_bucket" {
  name      = "my-application-assets-bucket"
  bundle_id = "small_1_0" # Choose bundle based on storage needs
}

# 2. Create the Lightsail Distribution
resource "aws_lightsail_distribution" "cdn" {
  name        = "my-lightsail-cdn"
  bundle_id   = "small_1_0" # Choose bundle based on transfer needs
  is_enabled  = true

  # Set the origin to the Lightsail bucket created above
  origin {
    name        = "my-s3-origin"
    region_name = aws_lightsail_bucket.origin_bucket.region
    bucket_name = aws_lightsail_bucket.origin_bucket.name
  }

  # Configure the default cache behavior
  default_cache_behavior {
    behavior = "cache"
  }

  # Optional: Configure cache settings (forwarding headers, cookies, etc.)
  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_headers {
      option = "none"
    }

    forwarded_cookies {
      option = "none"
    }

    forwarded_query_strings {
      option = false
    }
  }
}

