resource "aws_lightsail_distribution" "cdn" {
  name      = "my-lightsail-cdn"
  bundle_id = "small_1_0" # Pricing bundle (e.g., small_1_0, medium_1_0)

  origin {
    name             = aws_lightsail_instance.origin_instance.name
    region_name      = aws_lightsail_instance.origin_instance.availability_zone
    protocol_policy  = "http-only" # Or "https-only" depending on instance config
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0
    forwarded_headers {
      option = "none"
    }
    forwarded_cookies {
      option = "none"
    }
    forwarded_query_strings {
      option = "false"
    }
  }

  # Ensure the distribution is enabled
  is_enabled = true

  tags = {
    ManagedBy = "Terraform"
  }
}

# Output the Distribution Domain Name
