# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create an SNS topic for Glacier vault notifications (optional but recommended for job completion alerts)
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"
}

# Create the Amazon S3 Glacier Vault
resource "aws_glacier_vault" "long_term_storage" {
  name = "archival-data-vault"

  # Access policy defined in JSON to restrict management access
  access_policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Sid": "add-read-only-access",
            "Effect": "Allow",
            "Principal": "*",
            "Action": [
                "glacier:GetVaultNotifications",
                "glacier:ListJobs"
            ],
            "Resource": "arn:aws:glacier:us-east-1:*:vaults/archival-data-vault"
        }
    ]
}
EOF

  # Configure notification events
  notification {
    events   = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
    sns_topic = aws_sns_topic.glacier_notifications.arn
  }

  tags = {
    Environment = "Production"
    Purpose     = "LongTermArchiving"
    Terraform   = "true"
  }
}

# Output the ARN of the created Glacier Vault
output "glacier_vault_arn" {
  value       = aws_glacier_vault.long_term_storage.arn
  description = "The ARN of the Amazon S3 Glacier vault."
}

