extracted_code:
# Terraform configuration for AWS Long-term Storage and Backup Solution
# This setup includes an S3 bucket with Lifecycle rules for archival and AWS Backup for automated snapshots.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Data Retention
resource "aws_s3_bucket" "archive_storage" {
  bucket = "long-term-data-archive-${random_id.suffix.hex}"

  # Prevent accidental deletion of the backup bucket
  lifecycle {
    prevent_destroy = true
  }
}

# 2. Random ID for unique bucket naming
resource "random_id" "suffix" {
  byte_length = 4
}

# 3. Enable Versioning (Crucial for backups)
resource "aws_s3_bucket_versioning" "archive_versioning" {
  bucket = aws_s3_bucket.archive_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 4. Lifecycle Rules for Cost Optimization (Transition to Glacier)
resource "aws_s3_bucket_lifecycle_configuration" "archive_lifecycle" {
  bucket = aws_s3_bucket.archive_storage.id

  rule {
    id     = "archive-to-glacier"
    status = "Enabled"

    # Transition current versions to Standard-IA after 30 days
    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    # Transition current versions to Glacier Deep Archive after 90 days for long-term retention
    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    # Clean up non-current versions (older versions of the same file)
    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER"
    }

    noncurrent_version_expiration {
      noncurrent_days = 365
    }
  }
}

# 5. AWS Backup Vault
resource "aws_backup_vault" "main_vault" {
  name        = "long-term-backup-vault"
  kms_key_arn = aws_kms_key.backup_key.arn
}

# 6. KMS Key for Backup Encryption
resource "aws_kms_key" "backup_key" {
  description             = "KMS key for Backup Vault"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# 7. AWS Backup Plan
resource "aws_backup_plan" "retention_plan" {
  name = "long-term-retention-plan"

  rule {
    rule_name         = "daily-backup-7-year-retention"
    target_vault_name = aws_backup_vault.main_vault.name
    schedule          = "cron(0 5 ? * * *)" # Daily at 05:00 UTC

    lifecycle {
      cold_storage_after = 30   # Move to cold storage after 30 days
      delete_after       = 2555 # Retain for 7 years
    }
  }
}

# 8. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "backup.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 9. Backup Selection (Assign resources to the backup plan via tags)
resource "aws_backup_selection" "resource_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "tagged-resources-selection"
  plan_id      = aws_backup_plan.retention_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupPlan"
    value = "LongTerm"
  }
}

output "s3_bucket_name" {
  value = aws_s3_bucket.archive_storage.id
}

output "backup_vault_arn" {
  value = aws_backup_vault.main_vault.arn
}

