# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Amazon S3 Glacier Vault
resource "aws_glacier_vault" "archive_vault" {
  name = "company-archive-vault"

  notification {
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
    sns_topic = aws_sns_topic.glacier_notifications.arn
  }

  tags = {
    Environment = "Production"
    Service     = "DataArchiving"
  }
}

# SNS Topic for Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"
}

# 2. IAM Role for Data Lifecycle Manager (DLM)
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for DLM to manage snapshots and interaction
resource "aws_iam_role_policy" "dlm_lifecycle_policy" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:EnableFastSnapshotRestores"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*:*:snapshot/*"
      }
    ]
  })
}

# 3. AWS Data Lifecycle Manager (DLM) Policy
# Note: DLM traditionally manages EBS snapshots; archiving snapshots directly to S3 Glacier 
# is handled via the "archive_rule" within the lifecycle policy.
resource "aws_dlm_lifecycle_policy" "example" {
  description        = "DLM Policy to archive EBS snapshots to Glacier"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]
    target_tags = {
      ArchiveToGlacier = "true"
    }

    schedule {
      name = "DailySnapshotAndArchive"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 7
      }

      # Integration: Archiving the snapshot to S3 Glacier storage tier
      archive_rule {
        retain_rule {
          count = 30
        }
      }

      copy_tags = true
    }
  }
}

