# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Glacier Vault
resource "aws_glacier_vault" "example_vault" {
  name = "my-secure-glacier-vault"

  tags = {
    Environment = "Production"
  }
}

# 2. Define the Vault Lock Policy
# This policy prevents deletion of archives for a specific period (e.g., 365 days)
data "aws_iam_policy_document" "vault_lock_policy" {
  statement {
    sid    = "DenyDeleteIfArchiveAgeLessThanYear"
    effect = "Deny"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions = [
      "glacier:DeleteArchive",
    ]

    resources = [
      aws_glacier_vault.example_vault.arn,
    ]

    condition {
      test     = "NumericLessThan"
      variable = "glacier:ArchiveAgeInDays"
      values   = ["365"]
    }
  }
}

# 3. Apply the Vault Lock
# Note: This starts the lock process. To complete the lock, it usually requires
# a manual confirmation within 24 hours via the API 'complete-vault-lock'.
# Setting 'ignore_deletion_error = true' is often used in testing to allow Terraform to clean up.
resource "aws_glacier_vault_lock" "example_lock" {
  vault_name    = aws_glacier_vault.example_vault.name
  policy        = data.aws_iam_policy_document.vault_lock_policy.json
  complete_lock = false # Set to true only when you are ready to make the lock immutable
}

output "vault_arn" {
  value = aws_glacier_vault.example_vault.arn
}

