resource "aws_glacier_vault" "archive_vault" {
  name = "company-archive-vault"

  tags = {
    Environment = "Production"
    Purpose     = "Compliance"
  }
}

# 2. Define the Vault Lock Policy via IAM Policy Document
data "aws_iam_policy_document" "vault_lock_policy" {
  statement {
    sid    # In-progress lock policy
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions   = ["glacier:DeleteArchive"]
    resources = [aws_glacier_vault.archive_vault.arn]

    condition {
      test     = "NumericLessThan"
      variable = "glacier:ArchiveAgeInDays"
      values   = ["365"]
    }

    # Restrict deletion to prevent accidental data loss
    deny {
      test     = "Bool"
      variable = "aws:MultiFactorAuthPresent"
      values   = ["false"]
    }
  }
}

# 3. Enforce the policy with a Vault Lock
# Note: The 'complete_lock' attribute determines if the lock is immutable.
# If set to true, the lock cannot be changed or deleted after the 24-hour testing period.
resource "aws_glacier_vault_lock" "vault_enforcement" {
  vault_name    = aws_glacier_vault.archive_vault.name
  policy        = data.aws_iam_policy_document.vault_lock_policy.json
  complete_lock = false # Set to true only when ready to make the policy permanent
}

# 4. Standard Vault Access Policy (Optional/Separate from the Lock)
data "aws_iam_policy_document" "vault_access_policy" {
  statement {
    actions   = ["glacier:DescribeVault", "glacier:GetDataRetrievalPolicy"]
    resources = [aws_glacier_vault.archive_vault.arn]
    principals {
      type        = "AWS"
      identifiers = ["*"] # Adjust to specific ARNs for production
    }
  }
}

resource "aws_glacier_vault_policy" "standard_policy" {
  vault_name = aws_glacier_vault.archive_vault.name
  policy     = data.aws_iam_policy_document.vault_access_policy.json
}

