# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic to receive Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-archive-retrieval-topic"
}

# 2. Define an IAM policy document to allow Glacier to publish to the SNS Topic
data "aws_iam_policy_document" "sns_glacier_access" {
  statement {
    sid    = "AllowGlacierToPublish"
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["glacier.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = [aws_sns_topic.glacier_notifications.arn]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = ["arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/*"]
    }
  }
}

# 3. Apply the policy to the SNS Topic
resource "aws_sns_topic_policy" "default" {
  arn    = aws_sns_topic.glacier_notifications.arn
  policy = data.aws_iam_policy_document.sns_glacier_access.json
}

# 4. Create the S3 Glacier Vault with notifications configured
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-secure-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Environment = "production"
  }
}

# Data sources to fetch current AWS account and region for the policy
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# Output the SNS Topic ARN and Vault name
output "vault_name" {
  value = aws_glacier_vault.my_archive_vault.name
}

output "sns_topic_arn" {
  value = aws_sns_topic.glacier_notifications.arn
}

