# Terraform configuration for an AWS Network Load Balancer (NLB) linked to a t2.micro EC2 Instance

provider "aws" {
  region = "us-east-1"
}

# 1. Provide a VPC and Subnet
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 2. Security Group for EC2 (Allowing traffic from NLB)
resource "aws_security_group" "ec2_sg" {
  name        = "allow_nlb_traffic"
  description = "Allow incoming traffic on port 80"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Provision the t2.micro EC2 Instance
resource "aws_instance" "web_server" {
  ami           = "ami-0c7217cdde317cfec" # Amazon Linux 2 (Subject to region)
  instance_type = "t2.micro"
  subnet_id     = data.aws_subnets.default.ids[0]
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "Hello from NLB Backend" > /var/www/html/index.html
              EOF

  tags = {
    Name = "NLB-Backend-Instance"
  }
}

# 4. Create the Network Load Balancer (NLB)
resource "aws_lb" "network_lb" {
  name               = "basic-nlb"
  internal           = false
  load_balancer_type = "network"
  subnets            = data.aws_subnets.default.ids

  enable_deletion_protection = false
}

# 5. Create Target Group
resource "aws_lb_target_group" "nlb_tg" {
  name     = "nlb-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = data.aws_vpc.default.id

  health_check {
    protocol = "TCP"
    interval = 30
  }
}

# 6. Create Listener
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.network_lb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# 7. Register Instance with Target Group
resource "aws_lb_target_group_attachment" "tg_attachment" {
  target_group_arn = aws_lb_target_group.nlb_tg.arn
  target_id        = aws_instance.web_server.id
  port             = 80
}

output "nlb_dns_name" {
  value       = aws_lb.network_lb.dns_name
  description = "The DNS name of the Network Load Balancer"
}

