# Terraform configuration for an AWS Network Load Balancer using specific EIPs

provider "aws" {
  region = "us-east-1"
}

# 1. Allocate Elastic IPs (or use existing ones via data sources)
resource "aws_eip" "lb_eip_1" {
  domain = "vpc"
}

resource "aws_eip" "lb_eip_2" {
  domain = "vpc"
}

# 2. Create the Network Load Balancer with static IP mapping
# Note: Application Load Balancers (ALB) do not support static EIPs directly; 
# you must use a Network Load Balancer (NLB) for this requirement.
resource "aws_lb" "example" {
  name               = "static-ip-nlb"
  load_balancer_type = "network"

  subnet_mapping {
    subnet_id     = "subnet-0123456789abcdef0" # Replace with your Subnet ID
    allocation_id = aws_eip.lb_eip_1.id
  }

  subnet_mapping {
    subnet_id     = "subnet-0abcdef1234567890" # Replace with your Subnet ID
    allocation_id = aws_eip.lb_eip_2.id
  }

  tags = {
    Environment = "production"
  }
}

# 3. Define a Target Group
resource "aws_lb_target_group" "example_tg" {
  name     = "example-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = "vpc-0123456789abcdef0" # Replace with your VPC ID
}

# 4. Create a Listener
resource "aws_lb_listener" "example_listener" {
  load_balancer_arn = aws_lb.example.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.example_tg.arn
  }
}

output "load_balancer_ips" {
  value = [aws_eip.lb_eip_1.public_ip, aws_eip.lb_eip_2.public_ip]
  description = "The static IP addresses assigned to the Load Balancer."
}

