# Terraform configuration for an Internal AWS Application Load Balancer
# with specific private IP addresses assigned to its network interfaces.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Networking - VPC and Subnets
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Security Group
resource "aws_security_group" "lb_sg" {
  name        = "internal-lb-sg"
  description = "Allow internal traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Internal Application Load Balancer
# Note: To assign specific private IPs, we use the subnet_mapping block.
resource "aws_lb" "internal_lb" {
  name               = "my-internal-alb"
  internal           = true
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]

  # Assigning specific private IP addresses per subnet
  subnet_mapping {
    subnet_id            = aws_subnet.subnet_a.id
    private_ipv4_address = "10.0.1.50"
  }

  subnet_mapping {
    subnet_id            = aws_subnet.subnet_b.id
    private_ipv4_address = "10.0.2.50"
  }

  tags = {
    Environment = "production"
    Name        = "internal-fixed-ip-lb"
  }
}

# Target Group
resource "aws_lb_target_group" "tg" {
  name     = "internal-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# Listener
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.internal_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

