extracted_code:
# Terraform configuration to set up an Application Load Balancer (ALB)
# routing traffic to a Network Load Balancer (NLB) using an IP-based Target Group.

provider "aws" {
  region = "us-east-1"
}

# --- VPC and Networking ---
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "public_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# --- Network Load Balancer (Internal) ---
resource "aws_lb" "nlb" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]
}

resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type = "fixed-response"
    fixed_response {
      content_type = "text/plain"
      message_body = "Forwarded to NLB"
      status_code  = "200"
    }
  }
}

# --- Application Load Balancer (External) ---
resource "aws_security_group" "alb_sg" {
  name   = "alb-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "alb" {
  name               = "external-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]
}

# --- ALB Target Group pointing to NLB IP addresses ---
# Note: Since ALBs cannot target NLB DNS names directly in HCL, 
# we use the 'ip' target type.
resource "aws_lb_target_group" "alb_to_nlb" {
  name        = "alb-to-nlb-tg"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip"
}

# Data source or attachment mechanism to link NLB Private IPs to ALB Target Group
# In a production environment, you might use a Lambda function to keep these synced, 
# as NLB IPs can change unless assigned Elastic IPs.
resource "aws_lb_target_group_attachment" "nl_attachment" {
  count            = 1
  target_group_arn = aws_lb_target_group.alb_to_nlb.arn
  # This targets the NLB. Note: You would typically programmatically 
  # retrieve the Network Interface IPs of the NLB.
  target_id        = "10.0.1.50" 
}

resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_to_nlb.arn
  }
}

