# Terraform configuration for an AWS Application Load Balancer with a Fixed-Response Action

provider "aws" {
  region = "us-east-1"
}

# 1. Provide a VPC and Subnets (Assuming default or existing for this example)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "public_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. Security Group for the ALB
resource "aws_security_group" "alb_sg" {
  name        = "allow_http"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Application Load Balancer
resource "aws_lb" "fixed_response_lb" {
  name               = "example-fixed-response-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Environment = "production"
  }
}

# 4. Listener with Fixed-Response Action
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.fixed_response_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "fixed-response"

    fixed_response {
      content_type = "text/plain"
      message_body = "This is a fixed response from the Application Load Balancer."
      status_code  = "200"
    }
  }
}

output "alb_dns_name" {
  value = aws_lb.fixed_response_lb.dns_name
  description = "The DNS name of the load balancer"
}

