# Terraform configuration to create an Application Load Balancer with a Cognito Authentication Action

provider "aws" {
  region = "us-east-1"
}

# 1. Cognito User Pool
resource "aws_cognito_user_pool" "pool" {
  name = "auth-user-pool"
}

# 2. Cognito User Pool Client
resource "aws_cognito_user_pool_client" "client" {
  name         = "client"
  user_pool_id = aws_cognito_user_pool.pool.id
}

# 3. Cognito Domain (Required for ALB Authentication)
resource "aws_cognito_user_pool_domain" "main" {
  domain       = "auth-lb-example-domain"
  user_pool_id = aws_cognito_user_pool.pool.id
}

# 4. Networking Basics
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 5. Application Load Balancer
resource "aws_lb" "main" {
  name               = "auth-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

resource "aws_security_group" "lb_sg" {
  name   = "lb-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 6. Target Group (Required for the forward action after authentication)
resource "aws_lb_target_group" "tg" {
  name     = "app-targets"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# 7. ALB Listener with Authenticate Cognito Action
# Note: HTTPS is mandatory for Cognito authentication
resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/valid-cert-id" # Replace with valid certificate ARN

  default_action {
    type = "authenticate-cognito"

    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.pool.arn
      user_pool_client_id = aws_cognito_user_pool_client.client.id
      user_pool_domain    = aws_cognito_user_pool_domain.main.domain
    }
  }

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

