# Terraform configuration for an AWS Gateway Load Balancer (GWLB)

provider "aws" {
  region = "us-east-1"
}

# 1. VPC Definition
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

# 2. Subnets (GWLB requires at least one subnet)
resource "aws_subnet" "gwlb_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

# 3. Gateway Load Balancer
resource "aws_lb" "gwlb" {
  name               = "example-gwlb"
  load_balancer_type = "gateway"
  subnets            = [aws_subnet.gwlb_subnet.id]

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# 4. Target Group (GENEVE protocol on port 6081 is standard for GWLB)
resource "aws_lb_target_group" "gwlb_tg" {
  name     = "gwlb-target-group"
  port     = 6081
  protocol = "GENEVE"
  vpc_id   = aws_vpc.main.id

  health_check {
    port     = "80"
    protocol = "TCP"
  }
}

# 5. Listener
resource "aws_lb_listener" "gwlb_listener" {
  load_balancer_arn = aws_lb.gwlb.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gwlb_tg.arn
  }
}

# 6. Gateway Load Balancer Endpoint Service (Optional - to share the GWLB)
resource "aws_vpc_endpoint_service" "gwlb_service" {
  acceptance_required        = false
  gateway_load_balancer_arns = [aws_lb.gwlb.arn]
}

# 7. Gateway Load Balancer Endpoint (To route traffic to the GWLB)
resource "aws_vpc_endpoint" "gwlb_endpoint" {
  service_name      = aws_vpc_endpoint_service.gwlb_service.service_name
  vpc_id            = aws_vpc.main.id
  vpc_endpoint_type = "GatewayLoadBalancer"
  subnet_ids        = [aws_subnet.gwlb_subnet.id]
}

