# Terraform configuration for an AWS Application Load Balancer with an IP-based Target Group

provider "aws" {
  region = "us-east-1"
}

# --- VPC and Networking (Data sources assumed or minimal resources for context) ---
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# --- Security Group for ALB ---
resource "aws_security_group" "alb_sg" {
  name        = "allow_http"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Load Balancer ---
resource "aws_lb" "main" {
  name               = "ip-based-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  enable_deletion_protection = false
}

# --- IP-Based Target Group ---
resource "aws_lb_target_group" "ip_target_group" {
  name        = "ip-based-tg"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip" # Crucial setting for IP-based routing

  health_check {
    enabled             = true
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }
}

# --- Registering IP Targets ---
# These are example private IPs. In a real scenario, these would be the IPs of your containers or instances.
resource "aws_lb_target_group_attachment" "target_1" {
  target_group_arn = aws_lb_target_group.ip_target_group.arn
  target_id        = "10.0.1.10" # The IP address of the target
  port             = 80
}

resource "aws_lb_target_group_attachment" "target_2" {
  target_group_arn = aws_lb_target_group.ip_target_group.arn
  target_id        = "10.0.2.10" # The IP address of the target
  port             = 80
}

# --- Listener ---
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.ip_target_group.arn
  }
}

output "alb_dns_name" {
  value = aws_lb.main.dns_name
}

