    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgresql_instance" {
  identifier           = "mydb-postgres-instance"
  engine               = "postgres"
  engine_version       = "15.4" # Latest stable major version
  instance_class       = "db.t4g.large"
  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type         = "gp3"

  db_name              = "mydatabase"
  username             = "dbadmin"
  password             = "Password123!" # Ideally use a secrets manager or variable

  db_subnet_group_name   = aws_db_subnet_group.postgresql_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  publicly_accessible  = false
  skip_final_snapshot  = true
  multi_az             = false

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

output "db_instance_endpoint" {
  value = aws_db_instance.postgresql_instance.endpoint
}
