# This configuration provides a PostgreSQL setup (AWS RDS instance) 
# tuned with parameters specifically chosen to minimize memory overhead.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Parameter group focused on reducing memory footprint
resource "aws_db_parameter_group" "minimal_memory" {
  family = "postgres15"
  name   = "minimal-memory-pg"

  # Reduces the shared memory buffer used for caching data
  parameter {
    name  = "shared_buffers"
    value = "16384" # ~128MB (Reduced from default)
  }

  # Limits memory used for internal sort operations and hash tables before writing to disk
  parameter {
    name  = "work_mem"
    value = "1024" # 1MB (Minimum recommended)
  }

  # Limits memory for maintenance tasks (indexing, vacuuming)
  parameter {
    name  = "maintenance_work_mem"
    value = "16384" # 16MB
  }

  # Reduces memory used by the autovacuum process
  parameter {
    name  = "autovacuum_work_mem"
    value = "-1" # Follows maintenance_work_mem
  }

  # Decreases the amount of memory used for caching WAL data
  parameter {
    name  = "wal_buffers"
    value = "512" # ~4MB
  }

  # Reduces the number of max connections to lower memory overhead per process
  parameter {
    name  = "max_connections"
    value = "20"
  }

  # Effectively disables huge pages to save small overhead on small instances
  parameter {
    name  = "huge_pages"
    value = "off"
  }
}

resource "aws_db_instance" "minimal_db" {
  allocated_storage      = 20
  engine                 = "postgres"
  engine_version         = "15"
  instance_class         = "db.t4g.micro" # Smallest available instance with 2GB RAM
  db_name                = "minimaldb"
  username               = "dbadmin"
  password               = "ChooseASecurePassword123!" # Should be handled via secrets manager in production
  parameter_group_name   = aws_db_parameter_group.minimal_memory.name
  skip_final_snapshot    = true
  publicly_accessible    = false
  storage_type           = "gp3"

  tags = {
    Name = "MinimalMemoryPostgres"
  }
}

