# Terraform configuration to launch an AWS RDS instance from an existing snapshot

provider "aws" {
  region = "us-east-1"
}

# Variable for the snapshot identifier
variable "db_snapshot_id" {
  description = "The identifier of the existing DB snapshot (ARN or local ID)"
  type        = string
  default     = "my-existing-db-snapshot-id"
}

# Security Group for the RDS instance
resource "aws_security_group" "rds_sg" {
  name        = "rds-from-snapshot-sg"
  description = "Allow traffic to RDS"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust as per your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Launching RDS from Snapshot
# Note: When restoration from a snapshot occurs, 'engine' and 'username' 
# are inherited from the snapshot and should generally not be provided.
resource "aws_db_instance" "restored_db" {
  identifier           = "restored-db-instance"
  instance_class       = "db.t3.micro"
  snapshot_identifier  = var.db_snapshot_id
  db_subnet_group_name = "my-existing-db-subnet-group" # Replace with your subnet group
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Final snapshot settings
  skip_final_snapshot  = true
  publicly_accessible  = false

  tags = {
    Name        = "RestoredRDSInstance"
    Environment = "Production"
  }
}

output "rds_endpoint" {
  value       = aws_db_instance.restored_db.endpoint
  description = "The connection endpoint for the restored RDS instance"
}

reference:
