# Main Terraform configuration for an Amazon RDS instance with GP3 storage

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Security group to allow database access
resource "aws_security_group" "rds_sg" {
  name        = "rds-gp3-sg"
  description = "Allow inbound traffic to RDS"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Caution: Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance utilizing GP3 storage
resource "aws_db_instance" "default" {
  identifier           = "myapp-db-instance"
  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type         = "gp3" # Specified GP3 storage
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t4g.micro"
  db_name              = "mydb"
  username             = "admin"
  password             = "Password123!" # Ideally use a secret manager or variable
  parameter_group_name = "default.postgres15"
  skip_final_snapshot  = true
  publicly_accessible  = true

  # GP3 specific settings (Optional: default is 3000 IOPS and 125 MiB/s)
  iops                = 3000
  storage_throughput  = 125

  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  tags = {
    Name = "GP3-Postgres-RDS"
  }
}

output "db_instance_endpoint" {
  value = aws_db_instance.default.endpoint
}

