extracted_code:
# Terraform configuration to restore an Aurora MySQL cluster from S3 data (S3 Import)
# This requires the data in S3 to be in a format supported by the Percona XtraBackup tool or similar.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role to allow RDS to access S3
resource "aws_iam_role" "rds_s3_import_role" {
  name = "rds-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "rds_s3_import_policy" {
  name = "rds-s3-import-policy"
  role = aws_iam_role.rds_s3_import_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["s3:GetObject", "s3:ListBucket"]
        Resource = ["arn:aws:s3:::my-db-backup-bucket", "arn:aws:s3:::my-db-backup-bucket/*"]
      }
    ]
  })
}

# 2. Aurora DB Cluster restored from S3
# Note: s3_import is specifically for restoring from S3 backup files
resource "aws_rds_cluster" "restored_db" {
  cluster_identifier      = "restored-aurora-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.05.2"
  database_name           = "restored_db"
  master_username         = "admin"
  master_password         = "password123" # Use a secret manager in production
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true

  # Configuration for restoring data from S3
  s3_import {
    source_engine         = "mysql"
    source_engine_version = "8.0"
    bucket_name           = "my-db-backup-bucket"
    bucket_prefix         = "backups/mysql-backup"
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
  }
}

# 3. DB Cluster Instance
resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 1
  identifier         = "restored-db-instance-1"
  cluster_identifier = aws_rds_cluster.restored_db.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.restored_db.engine
  engine_version     = aws_rds_cluster.restored_db.engine_version
}

