# Terraform configuration for an AWS RDS instance with password managed by AWS Secrets Manager
# Using the default AWS KMS key for encryption

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the Secret in AWS Secrets Manager
resource "aws_secretsmanager_secret" "db_password_secret" {
  name        = "rds-master-password-secret-01"
  description = "Managed master password for RDS"
  # Using the default KMS key (aws/secretsmanager) by not specifying kms_key_id
}

# 2. Generate a random password to initialize the secret
resource "random_password" "master_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# 3. Store the password in the Secret version
resource "aws_secretsmanager_secret_version" "db_password_val" {
  secret_id     = aws_secretsmanager_secret.db_password_secret.id
  secret_string = random_password.master_password.result
}

# 4. Create the RDS Instance using the secret
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  identifier           = "mydb-instance"
  db_name              = "mydb"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"

  # Fetch password from the Secrets Manager resource
  password             = aws_secretsmanager_secret_version.db_password_val.secret_string

  parameter_group_name = "default.postgres15"
  skip_final_snapshot  = true
  publicly_accessible  = false

  # Enable storage encryption using the default KMS key
  storage_encrypted    = true

  # Ensure the secret is updated if the password changes
  lifecycle {
    ignore_changes = [
      password,
    ]
  }
}

# 5. Enable Secrets Manager Rotation/Management (Optional but recommended for full integration)
# Note: This attribute manages the password rotation via the Secrets Manager service directly
resource "aws_secretsmanager_secret_rotation" "rotation" {
  secret_id           = aws_secretsmanager_secret.db_password_secret.id
  rotation_rules {
    automatically_after_days = 30
  }

  # Requires a Lambda function for rotation (not fully implemented in this snippet)
  # rotation_lambda_arn = aws_lambda_function.example.arn 
}

