# Terraform configuration for an RDS Instance integrated with Secrets Manager and KMS

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. KMS Key for encryption of the Secret and DB at rest
resource "aws_kms_key" "db_kms_key" {
  description             = "KMS key for RDS credentials and storage"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

# 2. Secrets Manager Secret container
resource "aws_secretsmanager_secret" "db_secret" {
  name        = "rds-master-credentials-v2"
  kms_key_id  = aws_kms_key.db_kms_key.arn
  description = "Managed by Terraform: RDS Master Credentials"
}

# 3. RDS Instance with Managed Master User Password
# This configuration tells AWS to generate the password and store it in Secrets Manager automatically
resource "aws_db_instance" "default" {
  allocated_storage           = 20
  storage_type                = "gp3"
  engine                      = "postgres"
  engine_version              = "15.3"
  instance_class              = "db.t3.micro"
  db_name                     = "mydb"
