  cidr_block = "10.0.0.0/16"
}

# Create a Subnet
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

# Create the EFS File System
resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-token"
  encrypted      = true

  # Lifecycle policy to transition files to Infrequent Access (IA) storage
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  # Lifecycle policy to transition files back to Standard storage class on access
  lifecycle_policy {
    transition_to_primary_storage_class = "AFTER_1_ACCESS"
  }

  tags = {
    Name = "MyExampleEFS"
  }
}

# Create a Security Group for EFS (Allow NFS traffic on port 2049)
resource "aws_security_group" "efs_sg" {
  name        = "efs-access-sg"
  description = "Allow inbound NFS traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }
}

