}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Amazon EFS File System
resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-example"
  encrypted      = true

  tags = {
    Name = "MyExampleEFS"
  }
}

# 2. Create the EFS Resource-based Policy
# This policy enforces SSL and prevents root access by default, 
# while granting full control to the account owner.
resource "aws_efs_file_system_policy" "policy" {
  file_system_id = aws_efs_file_system.example.id

  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "ExampleEFSResourcePolicy"
    Statement = [
      {
        Sid    = "AllowGrantAccess"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Resource = aws_efs_file_system.example.arn
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite",
          "elasticfilesystem:ClientRootAccess"
        ]
        Condition = {
          Bool = {
            "aws:SecureTransport" = "true"
          }
        }
      }
    ]
  })
}

# 3. Reference Output
output "efs_id" {
  value = aws_efs_file_system.example.id
}

