# 1. Create the Amazon EFS File System
resource "aws_efs_file_system" "main" {
  creation_token = "my-efs-backup-enabled"
  encrypted      = true

  tags = {
    Name = "EFSWithAutomaticBackups"
  }
}

# 2. Enable Automatic Backups
# This resource manages the backup policy for the specified EFS file system.
resource "aws_efs_backup_policy" "policy" {
  file_system_id = aws_efs_file_system.main.id

  backup_policy {
