# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the network infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "efs-vpc"
  }
}

# Create a Subnet where the mount target will reside
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "efs-subnet"
  }
}

# Security group to allow NFS traffic (Port 2049)
resource "aws_security_group" "efs_sg" {
  name        = "allow_nfs"
  description = "Allow NFS traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create the EFS File System
resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-token"
  encrypted      = true

  tags = {
    Name = "MyProductEFS"
  }
}

# Create the EFS Mount Target
resource "aws_efs_mount_target" "mount" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

# Outputs for connectivity
output "efs_id" {
  value = aws_efs_file_system.example.id
}

output "efs_dns_name" {
