# Terraform configuration to provision an AWS Egress-only Internet Gateway

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# Assuming a VPC already exists, or creating a data source to fetch it
# For this example, we create a VPC to ensure the code is functional
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "main-vpc"
  }
}

# The Egress-Only Internet Gateway
resource "aws_egress_only_internet_gateway" "pike" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name        = "pike"
    permissions = "permissions"
  }
}

# Example Route Table entry to direct IPv6 traffic to the gateway
resource "aws_route_table" "ipv6_egress" {
  vpc_id = aws_vpc.main.id

  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.pike.id
  }

  tags = {
    Name = "pike-egress-route-table"
  }
}

