# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Provide an existing VPC or create a new one with IPv6 CIDR enabled
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "ipv6-enabled-vpc"
  }
}

# 2. Provision the Egress-Only Internet Gateway
resource "aws_egress_only_internet_gateway" "eoigw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-egress-only-gateway"
  }
}

# 3. Create a Subnet with IPv6 enabled
resource "aws_subnet" "private_ipv6" {
  vpc_id                          = aws_vpc.main.id
  cidr_block                      = "10.0.1.0/24"
  ipv6_cidr_block                 = cidrsubnet(aws_vpc.main.ipv6_cidr_block, 8, 1)
  assign_ipv6_address_on_creation = true

  tags = {
    Name = "private-ipv6-subnet"
  }
}

# 4. Create a Route Table and add a route for IPv6 traffic to the Egress-Only IGW
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  # This route allows all IPv6 egress traffic to the internet
  # while preventing any unsolicited inbound IPv6 traffic.
  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.eoigw.id
  }

  tags = {
    Name = "private-ipv6-route-table"
  }
}

# 5. Associate the Route Table with the Subnet
resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private_ipv6.id
  route_table_id = aws_route_table.private.id
}

