# Terraform configuration to provision a NAT Gateway with an existing EIP
# Required variables: subnet_id and allocation_id

resource "aws_nat_gateway" "main" {
  allocation_id = var.eip_allocation_id
  subnet_id     = var.subnet_id

  tags = {
    Name        = "main-nat-gateway"
    Environment = "production"
  }

  # To ensure proper ordering, it is recommended to add an explicit dependency 
  # on the Internet Gateway for the VPC if it were being created in the same stack.
}

variable "subnet_id" {
  description = "The Subnet ID in which to place the NAT Gateway. This must be a public subnet."
  type        = string
}

variable "eip_allocation_id" {
  description = "The Allocation ID of the Elastic IP address for the gateway."
  type        = string
}

output "nat_gateway_id" {
  description = "The ID of the NAT Gateway"
  value       = aws_nat_gateway.main.id
}

output "nat_gateway_public_ip" {
  description = "The public IP address of the NAT Gateway"
  value       = aws_nat_gateway.main.public_ip
}

