# AWS VPC Peering Configuration
# This configuration creates two VPCs ("peer" and "base") and establishes 
# a peering connection named "pike" between them.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the "peer" VPC
resource "aws_vpc" "peer" {
  cidr_block           = "10.0.0.0/24"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "peer"
  }
}

# 2. Create the "base" VPC
resource "aws_vpc" "base" {
  cidr_block           = "10.1.0.0/24"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "base"
  }
}

# 3. Create the VPC Peering connection "pike"
resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = aws_vpc.base.id
  peer_vpc_id = aws_vpc.peer.id
  auto_accept = true

  tags = {
    Name = "pike"
  }
}

# 4. Update Route Tables to allow traffic over the peering link
# Routing for the "base" VPC to reach "peer" CIDR
resource "aws_route" "base_to_peer" {
  route_table_id            = aws_vpc.base.main_route_table_id
  destination_cidr_block    = aws_vpc.peer.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
}

# Routing for the "peer" VPC to reach "base" CIDR
resource "aws_route" "peer_to_base" {
  route_table_id            = aws_vpc.peer.main_route_table_id
  destination_cidr_block    = aws_vpc.base.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
}

