# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Resource: VPC (Required to associate a Network ACL)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

# Resource: Network ACL (Permits all inbound and outbound traffic)
resource "aws_network_acl" "permit_all" {
  vpc_id = aws_vpc.main.id

  # Inbound Rule: Allow all traffic from every source
  ingress {
    protocol   = "-1" # -1 means all protocols
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  # Outbound Rule: Allow all traffic to every destination
  egress {
    protocol   = "-1"
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  tags = {
    Name = "allow-all-nacl"
  }
}

